COPY public.question_knowledge (id, database_id, question, answer) FROM stdin;
86f444c8-0e0e-4891-83b4-f2eed5032b7f	california_schools	What is the highest eligible free rate for K-12 students in the schools in Alameda County?	SELECT `Free Meal Count (K-12)` / `Enrollment (K-12)` FROM frpm WHERE `County Name` = 'Alameda' ORDER BY (CAST(`Free Meal Count (K-12)` AS REAL) / `Enrollment (K-12)`) DESC LIMIT 1
e9ec0541-a994-46d9-8636-d338aaf24bbe	california_schools	Please list the lowest three eligible free rates for students aged 5-17 in continuation schools.	SELECT `Free Meal Count (Ages 5-17)` / `Enrollment (Ages 5-17)` FROM frpm WHERE `Educational Option Type` = 'Continuation School' AND `Free Meal Count (Ages 5-17)` / `Enrollment (Ages 5-17)` IS NOT NULL ORDER BY `Free Meal Count (Ages 5-17)` / `Enrollment (Ages 5-17)` ASC LIMIT 3
76480c1b-d3f3-4899-93e2-cd6c26d01a2b	california_schools	Please list the zip code of all the charter schools in Fresno County Office of Education.	SELECT T2.Zip FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T1.`District Name` = 'Fresno County Office of Education' AND T1.`Charter School (Y/N)` = 1
03442656-32b0-4efa-9e74-52c797476e55	california_schools	What is the unabbreviated mailing street address of the school with the highest FRPM count for K-12 students?	SELECT T2.MailStreet FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode ORDER BY T1.`FRPM Count (K-12)` DESC LIMIT 1
5d9339be-6f42-4e81-a8bc-0cee415437c0	california_schools	Please list the phone numbers of the direct charter-funded schools that are opened after 2000/1/1.	SELECT T2.Phone FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T1.`Charter Funding Type` = 'Directly funded' AND T1.`Charter School (Y/N)` = 1 AND T2.OpenDate > '2000-01-01'
32c0a5f3-7265-4fcf-84d5-4a4479935573	california_schools	How many schools with an average score in Math greater than 400 in the SAT test are exclusively virtual?	SELECT COUNT(DISTINCT T2.School) FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T2.Virtual = 'F' AND T1.AvgScrMath > 400
72ece17a-4b1a-41b3-973e-f8c031a5606f	california_schools	Among the schools with the SAT test takers of over 500, please list the schools that are magnet schools or offer a magnet program.	SELECT T2.School FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T2.Magnet = 1 AND T1.NumTstTakr > 500
de40811b-049d-43dd-ab42-8778906e59cf	california_schools	What is the phone number of the school that has the highest number of test takers with an SAT score of over 1500?	SELECT T2.Phone FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.NumGE1500 DESC LIMIT 1
8f92055e-b9c1-4b86-bd42-8a2b971672c5	california_schools	What is the number of SAT test takers of the schools with the highest FRPM count for K-12 students?	SELECT NumTstTakr FROM satscores WHERE cds = ( SELECT CDSCode FROM frpm ORDER BY `FRPM Count (K-12)` DESC LIMIT 1 )
3f74da16-d82a-4630-a34e-43011c473ca3	california_schools	Among the schools with the average score in Math over 560 in the SAT test, how many schools are directly charter-funded?	SELECT COUNT(T2.`School Code`) FROM satscores AS T1 INNER JOIN frpm AS T2 ON T1.cds = T2.CDSCode WHERE T1.AvgScrMath > 560 AND T2.`Charter Funding Type` = 'Directly funded'
aa47f0c0-d78c-4a75-9dea-ad9f11c279f7	california_schools	For the school with the highest average score in Reading in the SAT test, what is its FRPM count for students aged 5-17?	SELECT T2.`FRPM Count (Ages 5-17)` FROM satscores AS T1 INNER JOIN frpm AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.AvgScrRead DESC LIMIT 1
606c9f1d-9143-47ab-bb22-eb6f2ec31b5c	california_schools	Please list the codes of the schools with a total enrollment of over 500.	SELECT T2.CDSCode FROM schools AS T1 INNER JOIN frpm AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.`Enrollment (K-12)` + T2.`Enrollment (Ages 5-17)` > 500
c675fd25-1d24-4334-bf18-9220bcaedc18	california_schools	Among the schools with an SAT excellence rate of over 0.3, what is the highest eligible free rate for students aged 5-17?	SELECT MAX(CAST(T1.`Free Meal Count (Ages 5-17)` AS REAL) / T1.`Enrollment (Ages 5-17)`) FROM frpm AS T1 INNER JOIN satscores AS T2 ON T1.CDSCode = T2.cds WHERE CAST(T2.NumGE1500 AS REAL) / T2.NumTstTakr > 0.3
2128a7a6-0009-4a5d-8a79-b71c46ac19d3	california_schools	Please list the phone numbers of the schools with the top 3 SAT excellence rate.	SELECT T1.Phone FROM schools AS T1 INNER JOIN satscores AS T2 ON T1.CDSCode = T2.cds ORDER BY CAST(T2.NumGE1500 AS REAL) / T2.NumTstTakr DESC LIMIT 3
a190ae74-52c7-480f-9284-6381a2dccc58	california_schools	List the top five schools, by descending order, from the highest to the lowest, the most number of Enrollment (Ages 5-17). Please give their NCES school identification number.	SELECT T1.NCESSchool FROM schools AS T1 INNER JOIN frpm AS T2 ON T1.CDSCode = T2.CDSCode ORDER BY T2.`Enrollment (Ages 5-17)` DESC LIMIT 5
3e7887be-8e2f-4947-aa93-f99c89e546eb	california_schools	Which active district has the highest average score in Reading?	SELECT T1.District FROM schools AS T1 INNER JOIN satscores AS T2 ON T1.CDSCode = T2.cds WHERE T1.StatusType = 'Active' ORDER BY T2.AvgScrRead DESC LIMIT 1
97c40037-9f69-44c4-b909-227b0011f2f5	california_schools	How many schools in merged Alameda have number of test takers less than 100?	SELECT COUNT(T1.CDSCode) FROM schools AS T1 INNER JOIN satscores AS T2 ON T1.CDSCode = T2.cds WHERE T1.StatusType = 'Merged' AND T2.NumTstTakr < 100 AND T1.County = 'Lake'
3871560a-b304-47bd-a456-e55c5f7190a3	california_schools	Rank schools by their average score in Writing where the score is greater than 499, showing their charter numbers.	SELECT CharterNum, AvgScrWrite, RANK() OVER (ORDER BY AvgScrWrite DESC) AS WritingScoreRank FROM schools AS T1  INNER JOIN satscores AS T2 ON T1.CDSCode = T2.cds WHERE T2.AvgScrWrite > 499 AND CharterNum is not null
692ea732-313b-4d17-9665-f5a9399b2b38	california_schools	How many schools in Fresno (directly funded) have number of test takers not more than 250?	SELECT COUNT(T1.CDSCode) FROM frpm AS T1 INNER JOIN satscores AS T2 ON T1.CDSCode = T2.cds WHERE T1.`Charter Funding Type` = 'Directly funded' AND T1.`County Name` = 'Fresno' AND T2.NumTstTakr <= 250
10c56489-129c-4e25-b0b5-7e3570e99e4b	california_schools	What is the phone number of the school that has the highest average score in Math?	SELECT T1.Phone FROM schools AS T1 INNER JOIN satscores AS T2 ON T1.CDSCode = T2.cds ORDER BY T2.AvgScrMath DESC LIMIT 1
2a637734-c0f4-41d4-aeef-4d447f38da31	california_schools	How many schools in Amador which the Low Grade is 9 and the High Grade is 12?	SELECT COUNT(T1.`School Name`) FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.County = 'Amador' AND T1.`Low Grade` = 9 AND T1.`High Grade` = 12
30960137-32c4-4387-86ee-a79333520e6d	california_schools	In Los Angeles how many schools have more than 500 free meals but less than 700 free or reduced price meals for K-12?	SELECT COUNT(CDSCode) FROM frpm WHERE `County Name` = 'Los Angeles' AND `Free Meal Count (K-12)` > 500 AND `FRPM Count (K-12)`< 700
3d534f0d-9904-4884-bdd5-9cdde6428347	california_schools	Which school in Contra Costa has the highest number of test takers?	SELECT sname FROM satscores WHERE cname = 'Contra Costa' AND sname IS NOT NULL ORDER BY NumTstTakr DESC LIMIT 1
8fedd407-4796-49ac-9276-9f580c1cccf5	california_schools	List the names of schools with more than 30 difference in enrollements between K-12 and ages 5-17? Please also give the full street adress of the schools.	SELECT T1.School, T1.Street FROM schools AS T1 INNER JOIN frpm AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.`Enrollment (K-12)` - T2.`Enrollment (Ages 5-17)` > 30
d5aa2265-d8c2-49b4-8cc9-6231c5107bd5	california_schools	Give the names of the schools with the percent eligible for free meals in K-12 is more than 0.1 and test takers whose test score is greater than or equal to 1500?	SELECT T2.`School Name` FROM satscores AS T1 INNER JOIN frpm AS T2 ON T1.cds = T2.CDSCode WHERE CAST(T2.`Free Meal Count (K-12)` AS REAL) / T2.`Enrollment (K-12)` > 0.1 AND T1.NumGE1500 > 0
efd8d5fb-21ce-48c0-aa32-baa6dd063d48	california_schools	Name schools in Riverside which the average of average math score for SAT is grater than 400, what is the funding type of these schools?	SELECT T1.sname, T2.`Charter Funding Type` FROM satscores AS T1 INNER JOIN frpm AS T2 ON T1.cds = T2.CDSCode WHERE T2.`District Name` LIKE 'Riverside%' GROUP BY T1.sname, T2.`Charter Funding Type` HAVING CAST(SUM(T1.AvgScrMath) AS REAL) / COUNT(T1.cds) > 400
1e77a78b-0534-4e62-9479-a7478c0a31d0	california_schools	State the names and full communication address of high schools in Monterey which has more than 800 free or reduced price meals for ages 15-17?	SELECT T1.`School Name`, T2.Street, T2.City, T2.State, T2.Zip FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.County = 'Monterey' AND T1.`Free Meal Count (Ages 5-17)` > 800 AND T1.`School Type` = 'High Schools (Public)'
ffc23e4b-a6a1-47e2-aaa3-2be08d84e488	california_schools	What is the average score in writing for the schools that were opened after 1991 or closed before 2000? List the school names along with the score. Also, list the communication number of the schools if there is any.	SELECT T2.School, T1.AvgScrWrite, T2.Phone FROM schools AS T2 LEFT JOIN satscores AS T1 ON T2.CDSCode = T1.cds WHERE strftime('%Y', T2.OpenDate) > '1991' OR strftime('%Y', T2.ClosedDate) < '2000'
b646e49c-76ec-4742-b0f4-d810abbf38ec	california_schools	Consider the average difference between K-12 enrollment and 15-17 enrollment of schools that are locally funded, list the names and DOC type of schools which has a difference above this average.	SELECT T2.School, T2.DOC FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.FundingType = 'Locally funded' AND (T1.`Enrollment (K-12)` - T1.`Enrollment (Ages 5-17)`) > (SELECT AVG(T3.`Enrollment (K-12)` - T3.`Enrollment (Ages 5-17)`) FROM frpm AS T3 INNER JOIN schools AS T4 ON T3.CDSCode = T4.CDSCode WHERE T4.FundingType = 'Locally funded')
8cd38820-d434-471b-ac3f-3ae832b021a3	california_schools	When did the first-through-twelfth-grade school with the largest enrollment open?	SELECT T2.OpenDate FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode ORDER BY T1.`Enrollment (K-12)` DESC LIMIT 1
d87ea6dc-536e-435f-82c8-f041c7a2b99f	california_schools	Which cities have the top 5 lowest enrollment number for students in grades 1 through 12?	SELECT T2.City FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode GROUP BY T2.City ORDER BY SUM(T1.`Enrollment (K-12)`) ASC LIMIT 5
48ad151e-98a8-4a49-bf77-52bc08072321	california_schools	What is the eligible free rate of the 10th and 11th schools with the highest enrolment for students in grades 1 through 12?	SELECT CAST(`Free Meal Count (K-12)` AS REAL) / `Enrollment (K-12)` FROM frpm ORDER BY `Enrollment (K-12)` DESC LIMIT 9, 2
d59f5cb4-20c6-447b-8047-8a992bde442a	california_schools	What is the eligible free or reduced price meal rate for the top 5 schools in grades 1-12 with the highest free or reduced price meal count of the schools with the ownership code 66?	SELECT CAST(T1.`FRPM Count (K-12)` AS REAL) / T1.`Enrollment (K-12)` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.SOC = 66 ORDER BY T1.`FRPM Count (K-12)` DESC LIMIT 5
698c64c2-e2cc-4a06-9f76-37ae236e613f	california_schools	If there are any, what are the websites address of the schools with a free meal count of 1,900-2,000 to students aged 5-17? Include the name of the school.	SELECT T2.Website, T1.`School Name` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T1.`Free Meal Count (Ages 5-17)` BETWEEN 1900 AND 2000 AND T2.Website IS NOT NULL
24036be9-05df-4194-b2cf-840eb3cd37a0	california_schools	What is the free rate for students between the ages of 5 and 17 at the school run by Kacey Gibson?	SELECT CAST(T2.`Free Meal Count (Ages 5-17)` AS REAL) / T2.`Enrollment (Ages 5-17)` FROM schools AS T1 INNER JOIN frpm AS T2 ON T1.CDSCode = T2.CDSCode WHERE T1.AdmFName1 = 'Kacey' AND T1.AdmLName1 = 'Gibson'
5ecab338-76f8-446e-8807-aac339a09512	california_schools	What is the administrator's email address of the chartered school with the fewest students enrolled in grades 1 through 12?	SELECT T2.AdmEmail1 FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T1.`Charter School (Y/N)` = 1 ORDER BY T1.`Enrollment (K-12)` ASC LIMIT 1
bee83cd1-823a-4a3f-9af6-ecc18fca2748	california_schools	Under whose administration is the school with the highest number of students scoring 1500 or more on the SAT? Indicate their full names.	SELECT T2.AdmFName1, T2.AdmLName1, T2.AdmFName2, T2.AdmLName2, T2.AdmFName3, T2.AdmLName3 FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.NumGE1500 DESC LIMIT 1
ae4c0acf-6dae-42fb-813c-0a8c47d426c3	california_schools	What is the complete address of the school with the lowest excellence rate? Indicate the Street, City, Zip and State.	SELECT T2.Street, T2.City, T2.State, T2.Zip FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY CAST(T1.NumGE1500 AS REAL) / T1.NumTstTakr ASC LIMIT 1
529ffe3c-a80e-4a26-9889-0998ca37d230	california_schools	What are the webpages for the Los Angeles County school that has between 2,000 and 3,000 test takers?	SELECT T2.Website FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T1.NumTstTakr BETWEEN 2000 AND 3000 AND T2.County = 'Los Angeles'
16a60610-f9a2-4bfa-96de-90d80f5d9a99	california_schools	What is the average number of test takers from Fresno schools that opened between 1/1/1980 and 12/31/1980?	SELECT AVG(T1.NumTstTakr) FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE strftime('%Y', T2.OpenDate) = '1980' AND T2.County = 'Fresno'
70055598-3068-42a0-8428-44fd077c3cc1	california_schools	What is the telephone number for the school with the lowest average score in reading in Fresno Unified?	SELECT T2.Phone FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T2.District = 'Fresno Unified' AND T1.AvgScrRead IS NOT NULL ORDER BY T1.AvgScrRead ASC LIMIT 1
0539c900-479c-4923-92b9-67fcaebf9906	california_schools	List the names of virtual schools that are among the top 5 in their respective counties based on average reading scores.	SELECT School FROM (SELECT T2.School,T1.AvgScrRead, RANK() OVER (PARTITION BY T2.County ORDER BY T1.AvgScrRead DESC) AS rnk FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T2.Virtual = 'F' ) ranked_schools WHERE rnk <= 5
ee006f27-6ed4-4777-b7b0-9b4404b308df	california_schools	What is the type of education offered in the school who scored the highest average in Math?	SELECT T2.EdOpsName FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.AvgScrMath DESC LIMIT 1
fd0b279c-2fb5-4f68-9d23-8b0d0509a66a	california_schools	What is the average math score of the school with the lowest average score for all subjects, and in which county is it located?	SELECT T1.AvgScrMath, T2.County FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T1.AvgScrMath IS NOT NULL ORDER BY T1.AvgScrMath + T1.AvgScrRead + T1.AvgScrWrite ASC LIMIT 1
4e3182e7-f129-434c-ba1d-02df384ba431	california_schools	What is the average writing score of the school who has the highest number of test takers whose total SAT sscores are greater or equal to 1500? Indicate the city to where the school is situated.	SELECT T1.AvgScrWrite, T2.City FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.NumGE1500 DESC LIMIT 1
02548c23-efa9-4f72-bac2-17954f2794da	california_schools	What is the average writing score of each of the schools managed by Ricci Ulrich? List the schools and the corresponding average writing scores.	SELECT T2.School, T1.AvgScrWrite FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T2.AdmFName1 = 'Ricci' AND T2.AdmLName1 = 'Ulrich'
a41a1d4b-2585-4c8d-9a6e-234dc21c5526	california_schools	Which state special schools have the highest number of enrollees from grades 1 through 12?	SELECT T2.School FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.DOC = 31 ORDER BY T1.`Enrollment (K-12)` DESC LIMIT 1
a6c76eb9-82ba-426e-a1a6-b4f10082ce49	california_schools	What is the monthly average number of schools that opened in Alameda County under the jurisdiction of the Elementary School District in 1980?	SELECT CAST(COUNT(School) AS REAL) / 12 FROM schools WHERE DOC = 52 AND County = 'Alameda' AND strftime('%Y', OpenDate) = '1980'
4ad589b5-9556-4fb1-99da-5597771fdec7	california_schools	What is the ratio of merged Unified School District schools in Orange County to merged Elementary School District schools?	SELECT CAST(SUM(CASE WHEN DOC = 54 THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN DOC = 52 THEN 1 ELSE 0 END) FROM schools WHERE StatusType = 'Merged' AND County = 'Orange'
f3afaedc-96cd-439c-b543-2b22833de5b0	california_schools	Which different county has the most number of closed schools? Please provide the name of each school as well as the closure date.	SELECT DISTINCT County, School, ClosedDate FROM schools WHERE County = ( SELECT County FROM schools WHERE StatusType = 'Closed' GROUP BY County ORDER BY COUNT(School) DESC LIMIT 1 ) AND StatusType = 'Closed' AND school IS NOT NULL
02d94c2e-e41f-4bd7-a678-fc0c9195eaa1	california_schools	What is the postal street address for the school with the 7th highest Math average? Indicate the school's name.	SELECT T2.MailStreet, T2.School FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.AvgScrMath DESC LIMIT 6, 1
8ef9935a-6308-4043-bef0-2d98e86f96f8	california_schools	In which mailing street address can you find the school that has the lowest average score in reading? Also give the school's name.	SELECT T2.MailStreet, T2.School FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T1.AvgScrRead IS NOT NULL ORDER BY T1.AvgScrRead ASC LIMIT 1
83f158f2-a668-446d-b70c-83ba6edabbbe	california_schools	What is the total number of schools whose total SAT scores are greater or equal to 1500 whose mailing city is Lakeport?	SELECT COUNT(T1.cds) FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T2.MailCity = 'Lakeport' AND (T1.AvgScrRead + T1.AvgScrMath + T1.AvgScrWrite) >= 1500
5dc02750-76ff-4bbd-b6d3-37e2daca353b	california_schools	How many test takers are there at the school/s whose mailing city address is in Fresno?	SELECT T1.NumTstTakr FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode WHERE T2.MailCity = 'Fresno'
7789bfa5-32cd-44df-93e0-4e2f39cb8929	california_schools	Please specify all of the schools and their related mailing zip codes that are under Avetik Atoian's administration.	SELECT School, MailZip FROM schools WHERE AdmFName1 = 'Avetik' AND AdmLName1 = 'Atoian'
6b1e0ac8-2657-4b47-a554-8e468903584b	california_schools	Of the schools with a mailing state address in California, what is the ratio of the schools located in the county of Colusa against the school located in the county of Humboldt?	SELECT CAST(SUM(CASE WHEN County = 'Colusa' THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN County = 'Humboldt' THEN 1 ELSE 0 END) FROM schools WHERE MailState = 'CA'
f962b64c-5a17-4185-9e0e-ccef50d6f28f	california_schools	Of all the schools with a mailing state address in California, how many are active in San Joaquin city?	SELECT COUNT(CDSCode) FROM schools WHERE City = 'San Joaquin' AND MailState = 'CA' AND StatusType = 'Active'
553df8bd-b4f6-412b-b7f6-b57a4d4d8b64	california_schools	What is the phone number and extension number for the school that had the 333rd highest average writing score?	SELECT T2.Phone, T2.Ext FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.AvgScrWrite DESC LIMIT 332, 1
8617a4af-546a-49fb-ba79-70942c10f9a7	california_schools	What is the phone number and extension number for the school with the zip code 95203-3704? Indicate the school's name.	SELECT Phone, Ext, School FROM schools WHERE Zip = '95203-3704'
b7ebe0be-0079-4987-a074-122d14968515	california_schools	What is the website for the schools under the administrations of Mike Larson and Dante Alvarez?	SELECT Website FROM schools WHERE (AdmFName1 = 'Mike' AND AdmLName1 = 'Larson') OR (AdmFName1 = 'Dante' AND AdmLName1 = 'Alvarez')
29d63227-6bcf-4fe8-be76-ceaad1638a25	california_schools	What are the websites for all the partially virtual chartered schools located in San Joaquin?	SELECT Website FROM schools WHERE County = 'San Joaquin' AND Virtual = 'P' AND Charter = 1
d58ee9a7-1cd4-4b1c-aa03-ba670b4500de	california_schools	How many chartered schools located in the city of Hickman are owned by the Elementary School District?	SELECT COUNT(School) FROM schools WHERE DOC = 52 AND Charter = 1 AND City = 'Hickman'
559430e8-4bbe-4479-9488-94455f5ce4fd	california_schools	What is the total number of non-chartered schools in the county of Los Angeles with a percent (%) of eligible free meals for grades 1 through 12 that is less than 0.18%?	SELECT COUNT(T2.School) FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.County = 'Los Angeles' AND T2.Charter = 0 AND CAST(T1.`Free Meal Count (K-12)` AS REAL) * 100 / T1.`Enrollment (K-12)` < 0.18
927927f7-7df2-4042-9041-c7d1d2284e50	california_schools	In chartered schools with charter number 00D2, what are the names of all the administrators? Include the name of the school and the city to which it belongs	SELECT AdmFName1, AdmLName1, School, City FROM schools WHERE Charter = 1 AND CharterNum = '00D2'
8a9b0851-7669-4282-9c61-d85b313d1578	california_schools	What is the total number of schools with a mailing city in Hickman belonging to the charter number 00D4?	SELECT COUNT(*) FROM schools WHERE CharterNum = '00D4' AND MailCity = 'Hickman'
e6283924-9a8b-40b9-a7d1-325649ae3cff	california_schools	What is the ratio in percentage of Santa Clara County schools that are locally funded compared to all other types of charter school funding?	SELECT CAST(SUM(CASE WHEN FundingType = 'Locally funded' THEN 1 ELSE 0 END) AS REAL) * 100 / SUM(CASE WHEN FundingType != 'Locally funded' THEN 1 ELSE 0 END) FROM schools WHERE County = 'Santa Clara' AND Charter = 1
960e3440-cdaf-4bc7-bf5e-a44989773abb	california_schools	Between 1/1/2000 to 12/31/2005, how many directly funded schools opened in the county of Stanislaus?	SELECT COUNT(School) FROM schools WHERE strftime('%Y', OpenDate) BETWEEN '2000' AND '2005' AND County = 'Stanislaus' AND FundingType = 'Directly funded'
ebb6c633-7c41-40b7-9c78-28ec0713427f	california_schools	What is the total amount of Community College District closure in 1989 in the city of San Francisco?	SELECT COUNT(School) FROM schools WHERE strftime('%Y', ClosedDate) = '1989' AND City = 'San Francisco' AND DOCType = 'Community College District'
c4885a82-0dca-465b-a561-087302426b0d	california_schools	Which county reported the most number of school closure in the 1980s with school wonership code belonging to Youth Authority Facilities (CEA)?	SELECT County FROM schools WHERE strftime('%Y', ClosedDate) BETWEEN '1980' AND '1989' AND StatusType = 'Closed' AND SOC = 11 GROUP BY County ORDER BY COUNT(School) DESC LIMIT 1
e0378ab5-4b66-4aea-87a2-df46f8330a53	california_schools	Please provide the National Center for Educational Statistics school district identification number for all schools with a School Ownership Code that are part of the State Special Schools.	SELECT NCESDist FROM schools WHERE SOC = 31
5703ba6e-a908-4dba-adce-6b4d9e78d6bb	california_schools	How many active and closed District Community Day Schools are there in the county of Alpine?	SELECT COUNT(School) FROM schools WHERE (StatusType = 'Closed' OR StatusType = 'Active') AND SOC = 69 AND County = 'Alpine'
c8a23459-970a-47f3-a474-eec51d1ed732	california_schools	What is the district code for the School that does not offer a magnet program in the city of Fresno?	SELECT T1.`District Code` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.City = 'Fresno' AND T2.Magnet = 0
20a802ee-ae33-4ef7-8a49-cdf6cc4d44b8	california_schools	How many students from the ages of 5 to 17 are enrolled at the State Special School school in Fremont for the 2014-2015 academic year?	SELECT T1.`Enrollment (Ages 5-17)` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.EdOpsCode = 'SSS' AND T2.City = 'Fremont' AND T1.`Academic Year` BETWEEN 2014 AND 2015
c4ffcadc-281f-4db4-aad7-82cfdce4f328	california_schools	What is the free or reduced price meal count for ages 5 to 17 in the Youth Authority School with a mailing street address of PO Box 1040?	SELECT T1.`FRPM Count (Ages 5-17)` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.MailStreet = 'PO Box 1040' AND T2.SOCType = 'Youth Authority Facilities'
1fde0cac-2c54-4bfc-80ca-89aa543f3f1a	california_schools	What is the lowest grade for the District Special Education Consortia School with National Center for Educational Statistics school district identification number of 0613360?	SELECT MIN(T1.`Low Grade`) FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.NCESDist = '0613360' AND T2.EdOpsCode = 'SPECON'
4067474d-c8ce-4189-b494-6726281efeae	california_schools	What is the educational level name for the schools with Breakfast Provision 2 in county code 37? Indicate the name of the school.	SELECT T2.EILName, T2.School FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T1.`NSLP Provision Status` = 'Breakfast Provision 2' AND T1.`County Code` = 37
cfc5a9bc-827d-4c4f-8b26-96ad3deda677	california_schools	What is the city location of the high school level school with Lunch Provision 2 whose lowest grade is 9 and the highest grade is 12 in the county of Merced?	SELECT T2.City FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T1.`NSLP Provision Status` = 'Lunch Provision 2' AND T2.County = 'Merced' AND T1.`Low Grade` = 9 AND T1.`High Grade` = 12 AND T2.EILCode = 'HS'
5f685262-553d-4959-93a6-9e9b0f247b3c	california_schools	Which schools served a grade span of Kindergarten to 9th grade in the county of Los Angeles and what is its Percent (%) Eligible FRPM (Ages 5-17)?	SELECT T2.School, T1.`FRPM Count (Ages 5-17)` * 100 / T1.`Enrollment (Ages 5-17)` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.County = 'Los Angeles' AND T2.GSserved = 'K-9'
74e31292-f96d-46d2-a57b-8e0842492e1a	california_schools	What is the most common type of grade span served in the city of Adelanto?	SELECT GSserved FROM schools WHERE City = 'Adelanto' GROUP BY GSserved ORDER BY COUNT(GSserved) DESC LIMIT 1
8b9ce2d1-82c4-421e-83ed-ae91f9b1cce7	california_schools	Between San Diego and Santa Barbara, which county offers the most number of schools that does not offer physical building? Indicate the amount.	SELECT County, COUNT(Virtual) FROM schools WHERE (County = 'San Diego' OR County = 'Santa Barbara') AND Virtual = 'F' GROUP BY County ORDER BY COUNT(Virtual) DESC LIMIT 1
77a6ef59-0100-4a24-a195-fb1109af5534	california_schools	What is the school type of the school with the highest latitude? Indicate the name of the school as well as the latitude coordinates.	SELECT T1.`School Type`, T1.`School Name`, T2.Latitude FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode ORDER BY T2.Latitude DESC LIMIT 1
802ff4aa-a389-4ad6-917f-79f12ed51451	california_schools	In which city can you find the school in the state of California with the lowest latitude coordinates and what is its lowest grade? Indicate the school name.	SELECT T2.City, T1.`Low Grade`, T1.`School Name` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.State = 'CA' ORDER BY T2.Latitude ASC LIMIT 1
1262a3c4-271e-4dfd-8435-2b17b3cb40a1	california_schools	What is the grade span offered in the school with the highest longitude?	SELECT GSoffered FROM schools ORDER BY ABS(longitude) DESC LIMIT 1
3fad20a7-1a7b-467b-b0f9-dfee7328545e	california_schools	Of the schools that offers a magnet program serving a grade span of Kindergarten to 8th grade, how many offers Multiple Provision Types? List the number of cities that offers a Kindergarten to 8th grade span and indicate how many schools are there serving such grade span for each city.	SELECT T2.City, COUNT(T2.CDSCode) FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.Magnet = 1 AND T2.GSoffered = 'K-8' AND T1.`NSLP Provision Status` = 'Multiple Provision Types' GROUP BY T2.City
23a38f06-5c3d-4fc3-8d4f-d313a9bc7dcd	california_schools	What are the two most common first names among the school administrators? Indicate the district to which they administer.	SELECT DISTINCT T1.AdmFName1, T1.District FROM schools AS T1 INNER JOIN ( SELECT admfname1 FROM schools GROUP BY admfname1 ORDER BY COUNT(admfname1) DESC LIMIT 2 ) AS T2 ON T1.AdmFName1 = T2.admfname1
bd24e6a8-6a79-458b-b22c-c82493e3c94c	california_schools	What is the Percent (%) Eligible Free (K-12) in the school administered by an administrator whose first name is Alusine. List the district code of the school.	SELECT T1.`Free Meal Count (K-12)` * 100 / T1.`Enrollment (K-12)`, T1.`District Code` FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.AdmFName1 = 'Alusine'
ac7bfdf3-7140-4697-a202-9d5c4d073bea	california_schools	What is the administrator's last name that oversees the school with Charter number 40? Indicate the district, the county where the school is situated, and the name of the school.	SELECT AdmLName1, District, County, School FROM schools WHERE CharterNum = '0040'
2d2de778-e8fa-499e-8228-fdda23671383	california_schools	What are the valid e-mail addresses of the administrator of the school located in the San Bernardino county, City of San Bernardino City Unified that opened between 1/1/2009 to 12/31/2010 whose school types are public Intermediate/Middle Schools and Unified Schools?	SELECT T2.AdmEmail1, T2.AdmEmail2 FROM frpm AS T1 INNER JOIN schools AS T2 ON T1.CDSCode = T2.CDSCode WHERE T2.County = 'San Bernardino' AND T2.City = 'San Bernardino' AND T2.DOC = 54 AND strftime('%Y', T2.OpenDate) BETWEEN '2009' AND '2010' AND T2.SOC = 62
707c8dc9-4bcc-4b08-9774-0896e72dfe51	california_schools	What is the administrator's email address for the school with the highest number of test takers who received SAT scores of at least 1500?Provide the name of the school.	SELECT T2.AdmEmail1, T2.School FROM satscores AS T1 INNER JOIN schools AS T2 ON T1.cds = T2.CDSCode ORDER BY T1.NumGE1500 DESC LIMIT 1
b3827848-023d-4c7f-8976-2868072d1099	financial	How many accounts who choose issuance after transaction are staying in East Bohemia region?	SELECT COUNT(T2.account_id) FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id WHERE T1.A3 = 'east Bohemia' AND T2.frequency = 'POPLATEK PO OBRATU'
9db0aa2b-413b-4b0a-9c62-d7f14bc43b18	financial	How many accounts who have region in Prague are eligible for loans?	SELECT COUNT(T1.account_id) FROM account AS T1 INNER JOIN loan AS T2 ON T1.account_id = T2.account_id INNER JOIN district AS T3 ON T1.district_id = T3.district_id WHERE T3.A3 = 'Prague'
0b7bff29-5f45-4d54-bb1f-2e30371e60c9	financial	The average unemployment ratio of 1995 and 1996, which one has higher percentage?	SELECT DISTINCT IIF(AVG(A13) > AVG(A12), '1996', '1995') FROM district
8911099e-b7bb-4288-92c1-7acf44aabf10	financial	List out the no. of districts that have female average salary is more than 6000 but less than 10000?	SELECT COUNT(DISTINCT T2.district_id)  FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.gender = 'F' AND T2.A11 BETWEEN 6000 AND 10000
6639271a-18e5-4888-bb19-ba2a1a94796f	financial	How many male customers who are living in North Bohemia have average salary greater than 8000?	SELECT COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.gender = 'M' AND T2.A3 = 'north Bohemia' AND T2.A11 > 8000
780de1ec-0ce5-4bc3-9695-3229e5f2e520	financial	List out the account numbers of female clients who are oldest and has lowest average salary, calculate the gap between this lowest average salary with the highest average salary?	SELECT T1.account_id , ( SELECT MAX(A11) - MIN(A11) FROM district ) FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN disp AS T3 ON T1.account_id = T3.account_id INNER JOIN client AS T4 ON T3.client_id = T4.client_id WHERE T2.district_id = ( SELECT district_id FROM client WHERE gender = 'F' ORDER BY birth_date ASC LIMIT 1 ) ORDER BY T2.A11 DESC LIMIT 1
ef64c03b-f51c-47a3-b701-108e79f61e94	financial	List out the account numbers of clients who are youngest and have highest average salary?	SELECT T1.account_id  FROM account AS T1 INNER JOIN disp AS T2 ON T1.account_id = T2.account_id INNER JOIN client AS T3 ON T2.client_id = T3.client_id INNER JOIN district AS T4 on T4.district_id = T1.district_id WHERE T2.client_id = ( SELECT client_id FROM client ORDER BY birth_date DESC LIMIT 1) GROUP BY T4.A11, T1.account_id
154a2e6d-e116-40fe-a7ad-227adc1873e1	financial	How many customers who choose statement of weekly issuance are Owner?	SELECT COUNT(T1.account_id) FROM account AS T1 INNER JOIN disp AS T2 ON T1.account_id = T2.account_id WHERE T2.type = 'OWNER' AND T1.frequency = 'POPLATEK TYDNE'
bc6595ed-a693-4758-8265-9b8876ce86c4	financial	List out the id number of client who choose statement of issuance after transaction are Disponent?	SELECT T2.client_id FROM account AS T1 INNER JOIN disp AS T2 ON T1.account_id = T2.account_id WHERE T1.frequency = 'POPLATEK PO OBRATU' AND T2.type = 'DISPONENT'
c32f83c9-73da-4cd3-bc7e-d89ec579c01f	financial	Among the accounts who have approved loan date in 1997, list out the accounts that have the lowest approved amount and choose weekly issuance statement.	SELECT T2.account_id FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id WHERE STRFTIME('%Y', T1.date) = '1997' AND T2.frequency = 'POPLATEK TYDNE' ORDER BY T1.amount LIMIT 1
2f1ba175-4774-4a3a-af88-d08e47cd2379	financial	Among the accounts who have loan validity more than 12 months, list out the accounts that have the highest approved amount and have account opening date in 1993.	SELECT T1.account_id FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id WHERE STRFTIME('%Y', T2.date) = '1993' AND T1.duration > 12 ORDER BY T1.amount DESC LIMIT 1
77bfaed3-78b6-4ac8-a740-cdc77f1ebaaa	financial	Among the account opened, how many female customers who were born before 1950 and stayed in Sokolov?	SELECT COUNT(T2.client_id) FROM district AS T1 INNER JOIN client AS T2 ON T1.district_id = T2.district_id WHERE T2.gender = 'F' AND STRFTIME('%Y', T2.birth_date) < '1950' AND T1.A2 = 'Sokolov'
cc5c01e4-e43a-4b96-bc98-17cc113b0f85	financial	List out the accounts who have the earliest trading date in 1995 ?	SELECT account_id FROM trans WHERE STRFTIME('%Y', date) = '1995' ORDER BY date ASC LIMIT 1
da10dd44-5059-4dac-899d-a1a6264732fc	financial	State different accounts who have account opening date before 1997 and own an amount of money greater than 3000USD	SELECT DISTINCT T2.account_id FROM trans AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id WHERE STRFTIME('%Y', T2.date) < '1997' AND T1.amount > 3000
37daabb2-1861-47ee-87e2-a399f9a6897e	financial	Which client issued his/her card in 1994/3/3, give his/her client id.	SELECT T2.client_id FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN card AS T3 ON T2.disp_id = T3.disp_id WHERE T3.issued = '1994-03-03'
2d8bca16-d2b6-492d-8d2a-d44f7f5beff4	financial	The transaction of 840 USD happened in 1998/10/14, when was this account opened?	SELECT T1.date FROM account AS T1 INNER JOIN trans AS T2 ON T1.account_id = T2.account_id WHERE T2.amount = 840 AND T2.date = '1998-10-14'
acac684a-745c-4f2f-ac45-391a3d5d59f2	financial	There was a loan approved in 1994/8/25, where was that account opened, give the district Id of the branch.	SELECT T1.district_id FROM account AS T1 INNER JOIN loan AS T2 ON T1.account_id = T2.account_id WHERE T2.date = '1994-08-25'
d7c0f0b9-94ec-4a1c-8ccf-a31b2955055c	financial	What is the biggest amount of transaction that the client whose card was opened in 1996/10/21 made?	SELECT T4.amount FROM card AS T1 JOIN disp AS T2 ON T1.disp_id = T2.disp_id JOIN account AS T3 on T2.account_id = T3.account_id JOIN trans AS T4 on T3.account_id = T4.account_id WHERE T1.issued = '1996-10-21' ORDER BY T4.amount DESC LIMIT 1
a280f1cd-e280-4877-b188-baf757ba1eb3	financial	What is the gender of the oldest client who opened his/her account in the highest average salary branch?	SELECT T2.gender FROM district AS T1 INNER JOIN client AS T2 ON T1.district_id = T2.district_id ORDER BY T1.A11 DESC, T2.birth_date ASC LIMIT 1
62570b46-0a20-432a-add1-8fdb2b232230	financial	For the client who applied the biggest loan, what was his/her first amount of transaction after opened the account?	SELECT T3.amount FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN trans AS T3 ON T2.account_id = T3.account_id ORDER BY T1.amount DESC, T3.date ASC LIMIT 1
9f7edaf8-51c5-4eaf-8b33-3124a3638174	financial	How many clients opened their accounts in Jesenik branch were women?	SELECT COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.gender = 'F' AND T2.A2 = 'Jesenik'
cbd3433c-5076-4742-ae8c-03f6c8551beb	financial	What is the disposition id of the client who made 5100 USD transaction in 1998/9/2?	SELECT T1.disp_id FROM disp AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN trans AS T3 ON T2.account_id = T3.account_id WHERE T3.date='1997-08-20' AND T3.amount = 5100
f442d4e3-2645-4c36-80ea-96ed18fa20d6	financial	How many accounts were opened in Litomerice in 1996?	SELECT COUNT(T2.account_id) FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id WHERE STRFTIME('%Y', T2.date) = '1996' AND T1.A2 = 'Litomerice'
e9dd7944-60a6-4dc9-916d-90ff9e946e11	toxicology	What elements are in a double type bond?	SELECT DISTINCT T1.element FROM atom AS T1 INNER JOIN bond AS T2 ON T1.molecule_id = T2.molecule_id INNER JOIN connected AS T3 ON T1.atom_id = T3.atom_id WHERE T2.bond_type = '='
511616ea-45e9-44b2-b955-cd635c7f2561	financial	For the female client who was born in 1976/1/29, which district did she opened her account?	SELECT T1.A2 FROM district AS T1 INNER JOIN client AS T2 ON T1.district_id = T2.district_id WHERE T2.birth_date = '1976-01-29' AND T2.gender = 'F'
dca6cdcb-c41b-44e5-a392-46c5ea5f5cd2	financial	For the client who applied 98832 USD loan in 1996/1/3, when was his/her birthday?	SELECT T4.birth_date FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN disp AS T3 ON T2.account_id = T3.account_id INNER JOIN client AS T4 ON T3.client_id = T4.client_id WHERE T1.date = '1996-01-03' AND T1.amount = 98832
f3e8f40a-0cf5-4ae4-b855-dbb2aa705cde	financial	For the first client who opened his/her account in Prague, what is his/her account ID?	SELECT T1.account_id FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T2.A3 = 'Prague' ORDER BY T1.date ASC LIMIT 1
1c672f06-4fe2-443e-80e6-59b46bd2dfcf	financial	For the branch which located in the south Bohemia with biggest number of inhabitants, what is the percentage of the male clients?	SELECT CAST(SUM(T1.gender = 'M') AS REAL) * 100 / COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T2.A3 = 'south Bohemia' GROUP BY T2.A4 ORDER BY T2.A4 DESC LIMIT 1
38f4940b-7acb-4e14-a9db-83bcfd23f083	financial	For the client whose loan was approved first in 1993/7/5, what is the increase rate of his/her account balance from 1993/3/22 to 1998/12/27?	SELECT CAST((SUM(IIF(T3.date = '1998-12-27', T3.balance, 0)) - SUM(IIF(T3.date = '1993-03-22', T3.balance, 0))) AS REAL) * 100 / SUM(IIF(T3.date = '1993-03-22', T3.balance, 0)) FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN trans AS T3 ON T3.account_id = T2.account_id WHERE T1.date = '1993-07-05'
f4111552-22f4-437e-a417-82283bd7d5a2	financial	What is the percentage of loan amount that has been fully paid with no issue.	SELECT (CAST(SUM(CASE WHEN status = 'A' THEN amount ELSE 0 END) AS REAL) * 100) / SUM(amount) FROM loan
7f2c8f1d-0024-4c05-97b5-e769415afbda	financial	For loan amount less than USD100,000, what is the percentage of accounts that is still running with no issue.	SELECT CAST(SUM(status = 'C') AS REAL) * 100 / COUNT(account_id) FROM loan WHERE amount < 100000
87be397e-bb4a-452c-81e7-04099a059c21	financial	For accounts in 1993 with statement issued after transaction, list the account ID, district name and district region.	SELECT T1.account_id, T2.A2, T2.A3 FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.frequency = 'POPLATEK PO OBRATU' AND STRFTIME('%Y', T1.date)= '1993'
91c2cb51-c7ce-40dc-88e7-5374c275f53a	financial	From Year 1995 to 2000, who are the accounts holders from 'east Bohemia'. State the account ID the frequency of statement issuance.	SELECT T1.account_id, T1.frequency FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T2.A3 = 'east Bohemia' AND STRFTIME('%Y', T1.date) BETWEEN '1995' AND '2000'
7a9e8b76-5e21-43bc-bfef-414021e65a8c	financial	List account ID and account opening date for accounts from 'Prachatice'.	SELECT T1.account_id, T1.date FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T2.A2 = 'Prachatice'
63d60049-17c6-403d-ae4b-957ab6be92af	financial	State the district and region for loan ID '4990'.	SELECT T2.A2, T2.A3 FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN loan AS T3 ON T1.account_id = T3.account_id WHERE T3.loan_id = 4990
4200e716-a8b7-4534-86d1-8f6c3e850897	financial	Provide the account ID, district and region for loan amount greater than USD300,000.	SELECT T1.account_id, T2.A2, T2.A3 FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN loan AS T3 ON T1.account_id = T3.account_id WHERE T3.amount > 300000
a327892a-e106-487a-b894-037598785324	financial	List the loan ID, district and average salary for loan with duration of 60 months.	SELECT T3.loan_id, T2.A2, T2.A11 FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN loan AS T3 ON T1.account_id = T3.account_id WHERE T3.duration = 60
059405fa-47e1-49ef-b105-5a49f0339ede	financial	For loans contracts which are still running where client are in debt, list the district of the and the state the percentage unemployment rate increment from year 1995 to 1996.	SELECT CAST((T3.A13 - T3.A12) AS REAL) * 100 / T3.A12 FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN district AS T3 ON T2.district_id = T3.district_id WHERE T1.status = 'D'
cf10c744-6dad-4e37-b4a8-4bc5e1b4a936	financial	Calculate the percentage of account from 'Decin' district for all accounts are opened in 1993.	SELECT CAST(SUM(T1.A2 = 'Decin') AS REAL) * 100 / COUNT(account_id) FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id WHERE STRFTIME('%Y', T2.date) = '1993'
e1e407f3-aff3-4bff-8206-dd19b568bae8	financial	List the account IDs with monthly issuance of statements.	SELECT account_id FROM account WHERE Frequency = 'POPLATEK MESICNE'
ca51a54b-b180-4701-bfc0-341fb418c784	financial	List the top nine districts, by descending order, from the highest to the lowest, the number of female account holders.	SELECT T2.A2, COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.gender = 'F' GROUP BY T2.district_id, T2.A2 ORDER BY COUNT(T1.client_id) DESC LIMIT 9
e036519a-a9eb-41b9-ad45-8651da80e1e2	financial	Which are the top ten withdrawals (non-credit card) by district names for the month of January 1996?	SELECT DISTINCT T1.A2 FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id INNER JOIN trans AS T3 ON T2.account_id = T3.account_id WHERE T3.type = 'VYDAJ' AND T3.date LIKE '1996-01%' ORDER BY A2 ASC LIMIT 10
47ec0535-1c48-4f76-b4af-490f9f1e1d92	financial	How many of the account holders in South Bohemia still do not own credit cards?	SELECT COUNT(T3.account_id) FROM district AS T1 INNER JOIN client AS T2 ON T1.district_id = T2.district_id INNER JOIN disp AS T3 ON T2.client_id = T3.client_id WHERE T1.A3 = 'south Bohemia' AND T3.type != 'OWNER'
60abb8b2-f841-45de-9fbd-786353f5e7ab	financial	Which district has highest active loan?	SELECT T2.A3 FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN loan AS T3 ON T1.account_id = T3.account_id WHERE T3.status IN ('C', 'D') GROUP BY T2.A3 ORDER BY SUM(T3.amount) DESC LIMIT 1
b8b6ca18-67bc-4084-96ed-c11691f180bd	financial	What is the average loan amount by male borrowers?	SELECT AVG(T4.amount) FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN account AS T3 ON T2.account_id = T3.account_id INNER JOIN loan AS T4 ON T3.account_id = T4.account_id WHERE T1.gender = 'M'
c0f4b5ea-ad36-4ddc-b645-46dd0b7c7fec	financial	In 1996, which districts have the highest unemployment rate? List their branch location and district name.	SELECT district_id, A2 FROM district ORDER BY A13 DESC LIMIT 1
e875ef82-6e10-45b2-91ff-10bed692229a	financial	In the branch where the largest number of crimes were committed in 1996, how many accounts were opened?	SELECT COUNT(T2.account_id) FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id GROUP BY T1.A16 ORDER BY T1.A16 DESC LIMIT 1
f40aaf05-3a87-4736-aac3-61a15e4b6b3b	financial	After making a credit card withdrawal, how many account/s with monthly issuance has a negative balance?	SELECT COUNT(T1.account_id) FROM trans AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id WHERE T1.balance < 0 AND T1.operation = 'VYBER KARTOU' AND T2.frequency = 'POPLATEK MESICNE'
56782dfe-0443-4764-ac38-14416d50025a	financial	Between 1/1/1995 and 12/31/1997, how many loans in the amount of at least 250,000 per account that chose monthly statement issuance were approved?	SELECT COUNT(T1.account_id) FROM account AS T1 INNER JOIN loan AS T2 ON T1.account_id = T2.account_id WHERE T2.date BETWEEN '1995-01-01' AND '1997-12-31' AND T1.frequency = 'POPLATEK MESICNE' AND T2.amount >= 250000
e7f04e8b-b69d-412d-a1cf-2b8d46d52e48	financial	How many accounts have running contracts in Branch location 1?	SELECT COUNT(T1.account_id) FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN loan AS T3 ON T1.account_id = T3.account_id WHERE T1.district_id = 1 AND (T3.status = 'C' OR T3.status = 'D')
7dbd615b-5dbe-4061-8c48-dec7822af38d	financial	In the branch where the second-highest number of crimes were committed in 1995 occurred, how many male clients are there?	SELECT COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.gender = 'M' AND T2.A15 = (SELECT T3.A15 FROM district AS T3 ORDER BY T3.A15 DESC LIMIT 1, 1)
457209ef-5d3e-4358-be1d-04b2603ec32a	financial	How many high-level credit cards have "OWNER" type of disposition?	SELECT COUNT(T1.card_id) FROM card AS T1 INNER JOIN disp AS T2 ON T1.disp_id = T2.disp_id WHERE T1.type = 'gold' AND T2.type = 'OWNER'
44185e70-c2f8-46c0-9ef7-65b9ae6cbaa1	financial	How many accounts are there in the district of "Pisek"?	SELECT COUNT(T1.account_id) FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T2.A2 = 'Pisek'
9b1bfb9c-0d62-46ac-ab83-05ed28e1edee	financial	Which districts have transactions greater than USS$10,000 in 1997?	SELECT T1.district_id FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN trans AS T3 ON T1.account_id = T3.account_id WHERE STRFTIME('%Y', T3.date) = '1997' GROUP BY T1.district_id HAVING SUM(T3.amount) > 10000
07d413c4-da5e-4308-bd01-9a30b26dd5f1	financial	Which accounts placed orders for household payment in Pisek?	SELECT DISTINCT T2.account_id FROM trans AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN district AS T3 ON T2.district_id = T3.district_id WHERE T1.k_symbol = 'SIPO' AND T3.A2 = 'Pisek'
919ba4fd-6a0d-48c6-b4d7-d504ff8e26a3	financial	What are the accounts that have gold credit cards?	SELECT T2.account_id FROM disp AS T2  INNER JOIN card AS T1 ON T1.disp_id = T2.disp_id  WHERE T1.type = 'gold'
8cf264dc-b017-4af7-ab9a-625a8469fcef	financial	How much is the average amount in credit card made by account holders in a month, in year 2021?	SELECT AVG(T4.amount) FROM card AS T1 INNER JOIN disp AS T2 ON T1.disp_id = T2.disp_id INNER JOIN account AS T3 ON T2.account_id = T3.account_id INNER JOIN trans AS T4 ON T3.account_id = T4.account_id WHERE STRFTIME('%Y', T4.date) = '1998' AND T4.operation = 'VYBER KARTOU'
2ba09346-a504-4262-b09a-0efe58e88f3d	financial	Who are the account holder identification numbers whose who have transactions on the credit card with the amount is less than the average, in 1998?	SELECT T1.account_id FROM trans AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id WHERE STRFTIME('%Y', T1.date) = '1998' AND T1.operation = 'VYBER KARTOU' AND T1.amount < (SELECT AVG(amount) FROM trans WHERE STRFTIME('%Y', date) = '1998')
7c4d754e-92fa-4d28-9da9-c27d71125854	financial	Who are the female account holders who own credit cards and also have loans?	SELECT T1.client_id FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN account AS T5 ON T2.account_id = T5.account_id INNER JOIN loan AS T3 ON T5.account_id = T3.account_id INNER JOIN card AS T4 ON T2.disp_id = T4.disp_id WHERE T1.gender = 'F'
5969d1b8-fe1c-4a9f-ba3a-99b895f1510b	financial	How many female clients' accounts are in the region of South Bohemia?	SELECT COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.gender = 'F' AND T2.A3 = 'south Bohemia'
ce03202a-9e7e-449b-a8e3-1df54dde9b07	financial	Please list the accounts whose district is Tabor that are eligible for loans.	SELECT T2.account_id FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id INNER JOIN disp AS T3 ON T2.account_id = T3.account_id WHERE T3.type = 'OWNER' AND T1.A2 = 'Tabor'
42690f1b-0257-4585-a399-7d3aeb1a15b6	financial	Please list the account types that are not eligible for loans, and the average income of residents in the district where the account is located exceeds $8000 but is no more than $9000.	SELECT T3.type FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id INNER JOIN disp AS T3 ON T2.account_id = T3.account_id WHERE T3.type != 'OWNER' AND T1.A11 BETWEEN 8000 AND 9000
c47354ae-d974-4c65-9f0b-d64e43bbf296	financial	How many accounts in North Bohemia has made a transaction with the partner's bank being AB?	SELECT COUNT(T2.account_id) FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id INNER JOIN trans AS T3 ON T2.account_id = T3.account_id WHERE T3.bank = 'AB' AND T1.A3 = 'north Bohemia'
8653cbc9-e925-4342-bdc3-e9de48904fa0	financial	Please list the name of the districts with accounts that made withdrawal transactions.	SELECT DISTINCT T1.A2 FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id INNER JOIN trans AS T3 ON T2.account_id = T3.account_id WHERE T3.type = 'VYDAJ'
0bd8c4b0-3374-4925-89b0-073cca198349	financial	What is the average number of crimes committed in 1995 in regions where the number exceeds 4000 and the region has accounts that are opened starting from the year 1997?	SELECT AVG(T1.A15) FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id WHERE STRFTIME('%Y', T2.date) >= '1997' AND T1.A15 > 4000
4ada4355-f501-41d8-b789-18c74aa36ab9	financial	How many 'classic' cards are eligible for loan?	SELECT COUNT(T1.card_id) FROM card AS T1 INNER JOIN disp AS T2 ON T1.disp_id = T2.disp_id WHERE T1.type = 'classic' AND T2.type = 'OWNER'
847289ce-49cc-47af-ad39-cd0c659d22e8	financial	How many male clients in 'Hl.m. Praha' district?	SELECT COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE T1.gender = 'M' AND T2.A2 = 'Hl.m. Praha'
6f4b4d20-9c38-499d-9cc6-45128b726324	financial	How many percent of 'Gold' cards were issued prior to 1998?	SELECT CAST(SUM(type = 'gold' AND STRFTIME('%Y', issued) < '1998') AS REAL) * 100 / COUNT(card_id) FROM card
5a441792-b145-4ec3-8070-79777af94d6b	financial	Who is the owner of the account with the largest loan amount?	SELECT T1.client_id FROM disp AS T1 INNER JOIN account AS T3 ON T1.account_id = T3.account_id INNER JOIN loan AS T2 ON T3.account_id = T2.account_id WHERE T1.type = 'OWNER' ORDER BY T2.amount DESC LIMIT 1
bee3c89a-5ef3-4095-be2e-155357e35259	financial	What is the number of committed crimes in 1995 in the district of the account with the id 532?	SELECT T1.A15 FROM district AS T1 INNER JOIN `account` AS T2 ON T1.district_id = T2.district_id WHERE T2.account_id = 532
b398c7ab-6a99-4d16-b5b2-80efba81bf6c	financial	What is the district Id of the account that placed the order with the id 33333?	SELECT T3.district_id FROM `order` AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN district AS T3 ON T2.district_id = T3.district_id WHERE T1.order_id = 33333
e8049005-b838-406d-ae2d-054b5cbee7e8	toxicology	Which type of label is the most numerous in atoms with hydrogen?	SELECT T.label FROM ( SELECT T2.label, COUNT(T2.molecule_id) FROM atom AS T1 INNER JOIN molecule AS T2 ON T1.molecule_id = T2.molecule_id WHERE T1.element = 'h' GROUP BY T2.label ORDER BY COUNT(T2.molecule_id) DESC LIMIT 1 ) t
eb40f62d-1c81-4dbb-bb10-4f1fe89f0b57	financial	List all the withdrawals in cash transactions that the client with the id 3356 makes.	SELECT T4.trans_id FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN account AS T3 ON T2.account_id = T3.account_id INNER JOIN trans AS T4 ON T3.account_id = T4.account_id WHERE T1.client_id = 3356 AND T4.operation = 'VYBER'
f9d3b00e-91d8-4b78-ba55-1a5e919ed860	financial	Among the weekly issuance accounts, how many have a loan of under 200000?	SELECT COUNT(T1.account_id) FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id WHERE T2.frequency = 'POPLATEK TYDNE' AND T1.amount < 200000
5b45bdc9-80b5-4fba-82ed-ea4f38a7375f	financial	What type of credit card does the client with the id 13539 own?	SELECT T3.type FROM disp AS T1 INNER JOIN client AS T2 ON T1.client_id = T2.client_id INNER JOIN card AS T3 ON T1.disp_id = T3.disp_id WHERE T2.client_id = 13539
cc16bf7d-72b3-4332-afd4-e8ae97aaba85	financial	What is the region of the client with the id 3541 from?	SELECT T1.A3 FROM district AS T1 INNER JOIN client AS T2 ON T1.district_id = T2.district_id WHERE T2.client_id = 3541
f2816de2-f806-4cfc-9cb3-69381e3893ed	financial	Which district has the most accounts with loan contracts finished with no problems?	SELECT T1.A2 FROM District AS T1 INNER JOIN Account AS T2 ON T1.District_id = T2.District_id INNER JOIN Loan AS T3 ON T2.Account_id = T3.Account_id WHERE T3.status = 'A' GROUP BY T1.District_id ORDER BY COUNT(T2.Account_id) DESC LIMIT 1
275ff702-7463-4c07-8663-48e75287de95	financial	Who placed the order with the id 32423?	SELECT T3.client_id FROM `order` AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN disp AS T4 ON T4.account_id = T2.account_id  INNER JOIN client AS T3 ON T4.client_id = T3.client_id WHERE T1.order_id = 32423
68969ae9-17f2-464f-8fbb-206637a72b6d	financial	Please list all the transactions made by accounts from district 5.	SELECT T3.trans_id FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id INNER JOIN trans AS T3 ON T2.account_id = T3.account_id WHERE T1.district_id = 5
711d57af-aea2-4434-b256-c36d230976e5	financial	How many of the accounts are from Jesenik district?	SELECT COUNT(T2.account_id) FROM district AS T1 INNER JOIN account AS T2 ON T1.district_id = T2.district_id WHERE T1.A2 = 'Jesenik'
de960a85-3731-4e42-89d7-bcd48ced5640	financial	List all the clients' IDs whose junior credit cards were issued after 1996.	SELECT T2.client_id FROM card AS T1 INNER JOIN disp AS T2 ON T1.disp_id = T2.disp_id WHERE T1.type = 'junior' AND T1.issued >= '1997-01-01'
2f8a2176-f7e7-4baf-b5ea-95bb4323f6df	financial	What percentage of clients who opened their accounts in the district with an average salary of over 10000 are women?	SELECT CAST(SUM(T2.gender = 'F') AS REAL) * 100 / COUNT(T2.client_id) FROM district AS T1 INNER JOIN client AS T2 ON T1.district_id = T2.district_id WHERE T1.A11 > 10000
00b7a26d-3723-494d-aada-70d5d3e98266	financial	What was the growth rate of the total amount of loans across all accounts for a male client between 1996 and 1997?	SELECT CAST((SUM(CASE WHEN STRFTIME('%Y', T1.date) = '1997' THEN T1.amount ELSE 0 END) - SUM(CASE WHEN STRFTIME('%Y', T1.date) = '1996' THEN T1.amount ELSE 0 END)) AS REAL) * 100 / SUM(CASE WHEN STRFTIME('%Y', T1.date) = '1996' THEN T1.amount ELSE 0 END) FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN disp AS T3 ON T3.account_id = T2.account_id INNER JOIN client AS T4 ON T4.client_id = T3.client_id WHERE T4.gender = 'M' AND T3.type = 'OWNER'
6bba8e54-465f-46e8-813a-18dd9a0ef19e	financial	How many credit card withdrawals were recorded after 1995?	SELECT COUNT(account_id) FROM trans WHERE STRFTIME('%Y', date) > '1995' AND operation = 'VYBER KARTOU'
924ca182-9bdb-40a2-b20e-40ca56f50069	financial	What was the difference in the number of crimes committed in East and North Bohemia in 1996?	SELECT SUM(IIF(A3 = 'east Bohemia', A16, 0)) - SUM(IIF(A3 = 'north Bohemia', A16, 0)) FROM district
bbbd481b-07f4-4ae8-b274-54ec132ceda7	financial	How many owner and disponent dispositions are there from account number 1 to account number 10?	SELECT SUM(type = 'OWNER') , SUM(type = 'DISPONENT') FROM disp WHERE account_id BETWEEN 1 AND 10
0aaaa32d-6bdf-481c-97b6-31a14cf4c3e6	financial	How often does account number 3 request an account statement to be released? What was the aim of debiting 3539 in total?	SELECT T1.frequency, T2.k_symbol FROM account AS T1 INNER JOIN (SELECT account_id, k_symbol, SUM(amount) AS total_amount FROM `order` GROUP BY account_id, k_symbol) AS T2 ON T1.account_id = T2.account_id WHERE T1.account_id = 3 AND T2.total_amount = 3539
059cf3df-318f-4ac9-b467-52701ea2b5b2	financial	What year was account owner number 130 born?	SELECT STRFTIME('%Y', T1.birth_date) FROM client AS T1 INNER JOIN disp AS T3 ON T1.client_id = T3.client_id INNER JOIN account AS T2 ON T3.account_id = T2.account_id WHERE T2.account_id = 130
188f56aa-b188-4bc9-9231-999315ec06b1	financial	How many accounts have an owner disposition and request for a statement to be generated upon a transaction?	SELECT COUNT(T1.account_id) FROM account AS T1 INNER JOIN disp AS T2 ON T1.account_id = T2.account_id WHERE T2.type = 'OWNER' AND T1.frequency = 'POPLATEK PO OBRATU'
b859448b-1725-4619-9b69-751c13842f2a	financial	What is the amount of debt that client number 992 has, and how is this client doing with payments?	SELECT T4.amount, T4.status FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN account AS T3 on T2.account_id = T3.account_id INNER JOIN loan AS T4 ON T3.account_id = T4.account_id WHERE T1.client_id = 992
780daa7a-3a7e-4582-ad78-e73d14859d1e	financial	What is the sum that client number 4's account has following transaction 851? Who owns this account, a man or a woman?	SELECT T4.balance, T1.gender FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN account AS T3 ON T2.account_id =T3.account_id INNER JOIN trans AS T4 ON T3.account_id = T4.account_id WHERE T1.client_id = 4 AND T4.trans_id = 851
3e60869f-0f33-4839-b8b2-f6effa971f21	financial	Which kind of credit card does client number 9 possess?	SELECT T3.type FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN card AS T3 ON T2.disp_id = T3.disp_id WHERE T1.client_id = 9
7ddb33b9-670c-4a11-b4ef-f51c841166d9	financial	How much, in total, did client number 617 pay for all of the transactions in 1998?	SELECT SUM(T3.amount) FROM client AS T1 INNER JOIN disp AS T4 ON T1.client_id = T4.client_id INNER JOIN account AS T2 ON T4.account_id = T2.account_id INNER JOIN trans AS T3 ON T2.account_id = T3.account_id WHERE STRFTIME('%Y', T3.date)= '1998' AND T1.client_id = 617
f1ab3cf2-997d-48df-8105-56281c28cecb	financial	Please provide a list of clients who were born between 1983 and 1987 and whose account branch is in East Bohemia, along with their IDs.	SELECT T1.client_id, T3.account_id FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN disp AS T4 ON T1.client_id = T4.client_id INNER JOIN account AS T3 ON T2.district_id = T3.district_id and T4.account_id = T3.account_id WHERE T2.A3 = 'east Bohemia' AND STRFTIME('%Y', T1.birth_date) BETWEEN '1983' AND '1987'
d0df6a02-d642-400e-a913-f6c11db9c3a8	financial	Please provide the IDs of the 3 female clients with the largest loans.	SELECT T1.client_id FROM client AS T1 INNER JOIN disp AS T4 on T1.client_id= T4.client_id INNER JOIN account AS T2 ON T4.account_id = T2.account_id  INNER JOIN loan AS T3 ON T2.account_id = T3.account_id and T4.account_id = T3.account_id WHERE T1.gender = 'F' ORDER BY T3.amount DESC LIMIT 3
c320c37d-da1d-4b85-9d25-80d535dda6d0	financial	How many male customers who were born between 1974 and 1976 have made a payment on their home in excess of $4000?	SELECT COUNT(T1.account_id) FROM trans AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id INNER JOIN disp AS T4 ON T2.account_id = T4.account_id INNER JOIN client AS T3 ON T4.client_id = T3.client_id WHERE STRFTIME('%Y', T3.birth_date) BETWEEN '1974' AND '1976' AND T3.gender = 'M' AND T1.amount > 4000 AND T1.k_symbol = 'SIPO'
065b7c21-21b2-46e5-a082-00451c0d6094	financial	How many accounts in Beroun were opened after 1996?	SELECT COUNT(account_id) FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE STRFTIME('%Y', T1.date) > '1996' AND T2.A2 = 'Beroun'
8c2f32c7-92c6-4f82-b191-ff92397a5adc	financial	How many female customers have a junior credit card?	SELECT COUNT(T1.client_id) FROM client AS T1 INNER JOIN disp AS T2 ON T1.client_id = T2.client_id INNER JOIN card AS T3 ON T2.disp_id = T3.disp_id WHERE T1.gender = 'F' AND T3.type = 'junior'
121efcc1-dc4d-466c-b3b1-27c806d63ab6	financial	What proportion of customers who have accounts at the Prague branch are female?	SELECT CAST(SUM(T2.gender = 'F') AS REAL) / COUNT(T2.client_id) * 100 FROM district AS T1 INNER JOIN client AS T2 ON T1.district_id = T2.district_id WHERE T1.A3 = 'Prague'
899b362e-2ee8-4499-b804-24930bb62f2f	financial	What percentage of male clients request for weekly statements to be issued?	SELECT CAST(SUM(T1.gender = 'M') AS REAL) * 100 / COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T3 ON T1.district_id = T3.district_id INNER JOIN account AS T2 ON T2.district_id = T3.district_id INNER JOIN disp as T4 on T1.client_id = T4.client_id AND T2.account_id = T4.account_id WHERE T2.frequency = 'POPLATEK TYDNE'
b173faed-7fa7-4ba8-8f04-f96a76c8363d	financial	How many clients who choose statement of weekly issuance are Owner?	SELECT COUNT(T2.account_id) FROM account AS T1 INNER JOIN disp AS T2 ON T2.account_id = T1.account_id WHERE T1.frequency = 'POPLATEK TYDNE' AND T2.type = 'OWNER'
59914b20-43d7-4506-a7e2-e40932f4d9b4	financial	Among the accounts who have loan validity more than 24 months, list out the accounts that have the lowest approved amount and have account opening date before 1997.	SELECT T1.account_id FROM loan AS T1 INNER JOIN account AS T2 ON T1.account_id = T2.account_id WHERE T1.duration > 24 AND STRFTIME('%Y', T2.date) < '1997' ORDER BY T1.amount ASC LIMIT 1
a348ad13-0bbd-4a55-90af-e6c421f63fe8	financial	Name the account numbers of female clients who are oldest and have lowest average salary?	SELECT T3.account_id FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN account AS T3 ON T2.district_id = T3.district_id INNER JOIN disp AS T4 ON T1.client_id = T4.client_id AND T4.account_id = T3.account_id  WHERE T1.gender = 'F' ORDER BY T1.birth_date ASC, T2.A11 ASC LIMIT 1
76fb773c-621a-4356-85d0-a4d164e339f9	financial	How many clients who were born in 1920 stay in east Bohemia?	SELECT COUNT(T1.client_id) FROM client AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id WHERE STRFTIME('%Y', T1.birth_date) = '1920' AND T2.A3 = 'east Bohemia'
0e103782-2b0e-4f3b-8ae1-62c037690b44	financial	How many loan accounts are for pre-payment of duration of 24 months with weekly issuance of statement.	SELECT COUNT(T2.account_id) FROM account AS T1 INNER JOIN loan AS T2 ON T1.account_id = T2.account_id WHERE T2.duration = 24 AND T1.frequency = 'POPLATEK TYDNE'
cafd7ad9-4506-4719-8f74-1c35a78f5e51	financial	What is the average amount of loan which are still on running contract with statement issuance after each transaction?	SELECT AVG(T2.amount) FROM account AS T1 INNER JOIN loan AS T2 ON T1.account_id = T2.account_id WHERE T2.status IN ('C', 'D') AND T1.frequency = 'POPLATEK PO OBRATU'
5be44400-88de-45c7-a52b-8b3d20f57d67	financial	List all ID and district for clients that can only have the right to issue permanent orders or apply for loans.	SELECT T3.client_id, T2.district_id, T2.A2 FROM account AS T1 INNER JOIN district AS T2 ON T1.district_id = T2.district_id INNER JOIN disp AS T3 ON T1.account_id = T3.account_id WHERE T3.type = 'OWNER'
a5fb9df8-45dc-42c4-8168-a40e580f7cb6	financial	Provide the IDs and age of the client with high level credit card, which is eligible for loans.	SELECT T1.client_id, STRFTIME('%Y', CURRENT_TIMESTAMP) - STRFTIME('%Y', T3.birth_date) FROM disp AS T1 INNER JOIN card AS T2 ON T2.disp_id = T1.disp_id INNER JOIN client AS T3 ON T1.client_id = T3.client_id WHERE T2.type = 'gold' AND T1.type = 'OWNER'
3d479861-6520-46e8-b8e5-7d4b0405d28f	toxicology	What is the most common bond type?	SELECT T.bond_type FROM ( SELECT bond_type, COUNT(bond_id) FROM bond GROUP BY bond_type ORDER BY COUNT(bond_id) DESC LIMIT 1 ) AS T
ece5f83e-10f6-42e2-bbab-5f9b8d4021a3	toxicology	In the non-carcinogenic molecules, how many contain chlorine atoms?	SELECT COUNT(DISTINCT T1.molecule_id) FROM molecule AS T1 INNER JOIN atom AS T2 ON T1.molecule_id = T2.molecule_id WHERE T2.element = 'cl' AND T1.label = '-'
ac49578f-350b-4a1d-81df-d02595e03192	toxicology	Calculate the average number of oxygen atoms in single-bonded molecules.	SELECT AVG(oxygen_count) FROM (SELECT T1.molecule_id, COUNT(T1.element) AS oxygen_count FROM atom AS T1 INNER JOIN bond AS T2 ON T1.molecule_id = T2.molecule_id  WHERE T2.bond_type = '-' AND T1.element = 'o'  GROUP BY T1.molecule_id) AS oxygen_counts
456146d3-a1ac-46c5-95bf-c776a2738784	toxicology	On average how many carcinogenic molecules are single bonded?	SELECT AVG(single_bond_count) FROM (SELECT T3.molecule_id, COUNT(T1.bond_type) AS single_bond_count FROM bond AS T1  INNER JOIN atom AS T2 ON T1.molecule_id = T2.molecule_id INNER JOIN molecule AS T3 ON T3.molecule_id = T2.molecule_id WHERE T1.bond_type = '-' AND T3.label = '+' GROUP BY T3.molecule_id) AS subquery
c9e0ceaa-27a9-455c-9edc-d562357a02d4	toxicology	In the molecule containing sodium atoms, how many are non-carcinogenic?	SELECT COUNT(DISTINCT T2.molecule_id) FROM atom AS T1 INNER JOIN molecule AS T2 ON T1.molecule_id = T2.molecule_id WHERE T1.element = 'na' AND T2.label = '-'
5e601b69-6dc6-4980-a2d9-6ebd53f2da68	toxicology	Find the triple-bonded molecules which are carcinogenic.	SELECT DISTINCT T2.molecule_id FROM bond AS T1 INNER JOIN molecule AS T2 ON T1.molecule_id = T2.molecule_id WHERE T1.bond_type = '#' AND T2.label = '+'
ce5cab44-b151-4ba7-86d4-5fcde3dc3497	toxicology	What is the percentage of carbon in double-bond molecules?	SELECT CAST(COUNT(DISTINCT CASE WHEN T1.element = 'c' THEN T1.atom_id ELSE NULL END) AS REAL) * 100 / COUNT(DISTINCT T1.atom_id) FROM atom AS T1 INNER JOIN bond AS T2 ON T1.molecule_id = T2.molecule_id WHERE T2.bond_type = '='
cdf2f3c3-7459-4f70-8b70-1523191dc029	toxicology	How many triple type bonds are there?	SELECT COUNT(T.bond_id) FROM bond AS T WHERE T.bond_type = '#'
1aaafbc1-718d-42b5-aee5-d2b28e158e15	toxicology	In how many atoms is there no bromine?	SELECT COUNT(DISTINCT T.atom_id) FROM atom AS T WHERE T.element <> 'br'
ac23655b-1789-4454-8ece-14caf0de19a6	toxicology	Of the first 100 molecules in number order, how many are carcinogenic?	SELECT COUNT(T.molecule_id) FROM molecule AS T WHERE molecule_id BETWEEN 'TR000' AND 'TR099' AND T.label = '+'
56d09be0-2435-431e-8182-3498c1c098dc	toxicology	Identify by their ID the molecules in which there is carbon.	SELECT T.molecule_id FROM atom AS T WHERE T.element = 'c'
