16d9d121-d1aa-49e6-8015-b66ba848bcf7	toxicology	What atoms are connected in single type bonds?	SELECT T2.atom_id, T2.atom_id2 FROM bond AS T1 INNER JOIN connected AS T2 ON T1.bond_id = T2.bond_id WHERE T1.bond_type = '-'
