6450c422-1113-4cc7-8f6a-fc0573efb887	toxicology	Identify all connected atoms with a triple bond.	SELECT T2.atom_id, T2.atom_id2 FROM bond AS T1 INNER JOIN connected AS T2 ON T1.bond_id = T2.bond_id WHERE T1.bond_type = '#'
98c6ca7d-259e-4db6-9e33-51cce2527ebc	toxicology	Identify all the atoms that are connected to the atoms of the TR181 molecule.	SELECT T2.atom_id, T2.atom_id2 FROM atom AS T1 INNER JOIN connected AS T2 ON T2.atom_id = T1.atom_id WHERE T1.molecule_id = 'TR181'
aff8f114-07a0-4b99-a451-87ae8c7eb7e7	toxicology	What percentage of carcinogenic-type molecules does not contain fluorine?	SELECT CAST(COUNT(DISTINCT CASE WHEN T1.element <> 'f' THEN T2.molecule_id ELSE NULL END) AS REAL) * 100 / COUNT(DISTINCT T2.molecule_id) FROM atom AS T1 INNER JOIN molecule AS T2 ON T1.molecule_id = T2.molecule_id WHERE T2.label = '+'
69c4ab3d-16ef-4a66-9cea-9f3907ba62ad	toxicology	What is the percentage of carcinogenic molecules in triple type bonds?	SELECT CAST(COUNT(DISTINCT CASE WHEN T2.label = '+' THEN T2.molecule_id ELSE NULL END) AS REAL) * 100 / COUNT(DISTINCT T2.molecule_id) FROM atom AS T1 INNER JOIN molecule AS T2 ON T1.molecule_id = T2.molecule_id INNER JOIN bond AS T3 ON T2.molecule_id = T3.molecule_id WHERE T3.bond_type = '#'
f82fd4e4-62f5-468a-b4d4-316b979ac4cd	toxicology	Please list top three elements of the toxicology of the molecule TR000 in alphabetical order.	SELECT DISTINCT T.element FROM atom AS T WHERE T.molecule_id = 'TR000' ORDER BY T.element LIMIT 3
