bc245b87-4856-4782-acfc-4e5f876e0d3c	toxicology	What is the total number of molecules with double bonded oxygen?	SELECT COUNT(DISTINCT T1.molecule_id) FROM atom AS T1 INNER JOIN bond AS T2 ON T1.molecule_id = T2.molecule_id WHERE T2.bond_type = '=' AND T1.element = 'o'
cd7bac99-4845-469a-b485-2a01d4fb5244	toxicology	in molecules with triple bonds, how many of them are not carcinogenic?	SELECT COUNT(DISTINCT T1.molecule_id) FROM molecule AS T1 INNER JOIN bond AS T2 ON T1.molecule_id = T2.molecule_id WHERE T2.bond_type = '#' AND T1.label = '-'
badb67cf-c9c4-41be-86b4-f477d2bece70	toxicology	List the element and bond type included in the molecule with molecule ID of TR002.	SELECT DISTINCT T1.element, T2.bond_type FROM atom AS T1 INNER JOIN bond AS T2 ON T1.molecule_id = T2.molecule_id WHERE T1.molecule_id = 'TR002'
0b5c0c5e-eda3-4dbf-9752-2585d6c08d94	toxicology	What is the atom ID of double bonded carbon in TR012 molecule?	SELECT T1.atom_id FROM atom AS T1 INNER JOIN molecule AS T2 ON T1.molecule_id = T2.molecule_id INNER JOIN bond AS T3 ON T2.molecule_id = T3.molecule_id WHERE T2.molecule_id = 'TR012' AND T3.bond_type = '=' AND T1.element = 'c'
223bcc46-f8ba-4e65-b086-fa4855a517ff	toxicology	List the atom ID of the carcinogenic molecule that contains oxygen?	SELECT T1.atom_id FROM atom AS T1 INNER JOIN molecule AS T2 ON T1.molecule_id = T2.molecule_id WHERE T1.element = 'o' AND T2.label = '+'
