f2315bda-0903-4340-b0ce-cec3f71a0aff	superhero	What is Abomination's eye colour?	SELECT T2.colour FROM superhero AS T1 INNER JOIN colour AS T2 ON T1.eye_colour_id = T2.id WHERE T1.superhero_name = 'Abomination'
519b8668-2e26-4870-8f39-9c13ed35039f	superhero	Name the tallest superhero.	SELECT superhero_name FROM superhero ORDER BY height_cm DESC LIMIT 1
a5de2f55-826c-42dc-8dc4-66286bfa60a2	superhero	Name the superhero, otherwise known as Charles Chandler.	SELECT superhero_name FROM superhero WHERE full_name = 'Charles Chandler'
e865b1a8-0294-4f66-abae-307319eaab42	superhero	Among all superheroes created by George Lucas, identify the percentage of female superheroes.	SELECT CAST(COUNT(CASE WHEN T3.gender = 'Female' THEN 1 ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) FROM superhero AS T1 INNER JOIN publisher AS T2 ON T1.publisher_id = T2.id INNER JOIN gender AS T3 ON T1.gender_id = T3.id WHERE T2.publisher_name = 'George Lucas'
d1001e26-3a5c-4928-aa1c-1f74520a5946	superhero	Among all superheroes in Marvel Comics, identify the percentage of 'good' superheroes.	SELECT CAST(COUNT(CASE WHEN T3.alignment = 'Good' THEN T1.id ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) FROM superhero AS T1 INNER JOIN publisher AS T2 ON T1.publisher_id = T2.id INNER JOIN alignment AS T3 ON T1.alignment_id = T3.id WHERE T2.publisher_name = 'Marvel Comics'
5bb921a4-4cb6-44bf-a1fa-0639b01f4157	superhero	What is the total number of superheroes that have John as their first name?	SELECT COUNT(id) FROM superhero WHERE full_name LIKE 'John%'
ca7d70e1-ca7a-4cbe-85e1-d3b8f9e76c73	superhero	Give the hero ID of superhero with the lowest attribute value.	SELECT hero_id FROM hero_attribute WHERE attribute_value = ( SELECT MIN(attribute_value) FROM hero_attribute )
7829df77-5c66-4add-877b-47cfae793265	superhero	Provide the full name of the superhero named Alien.	SELECT full_name FROM superhero WHERE superhero_name = 'Alien'
797a4806-5d29-4dd8-b942-ac9c98955643	superhero	In superheroes with weight less than 100, list the full name of the superheroes with brown eyes.	SELECT T1.full_name FROM superhero AS T1 INNER JOIN colour AS T2 ON T1.eye_colour_id = T2.id WHERE T1.weight_kg < 100 AND T2.colour = 'Brown'
35135d68-625a-4fc0-8dc7-61ce329de73e	superhero	List the attribute value of the superhero named Aquababy.	SELECT T2.attribute_value FROM superhero AS T1 INNER JOIN hero_attribute AS T2 ON T1.id = T2.hero_id WHERE T1.superhero_name = 'Aquababy'
16030f26-877e-46c8-ad6e-4c1ec1a88286	superhero	Provide the weight and race of the superhero with superhero ID 40.	SELECT T1.weight_kg, T2.race FROM superhero AS T1 INNER JOIN race AS T2 ON T1.race_id = T2.id WHERE T1.id = 40
c159ef38-f675-4286-b658-ef23975170c7	superhero	Calculate the average height of all neutral superheroes.	SELECT AVG(T1.height_cm) FROM superhero AS T1 INNER JOIN alignment AS T2 ON T1.alignment_id = T2.id WHERE T2.alignment = 'Neutral'
0554af5b-d232-411d-9123-5511ac5366c1	superhero	List the hero ID of superheroes have intellegence as their power.	SELECT T1.hero_id FROM hero_power AS T1 INNER JOIN superpower AS T2 ON T1.power_id = T2.id WHERE T2.power_name = 'Intelligence'
9b3a1068-7517-46ae-b7ba-e7370647ea46	superhero	Give the eye colour of Blackwulf.	SELECT T2.colour FROM superhero AS T1 INNER JOIN colour AS T2 ON T1.eye_colour_id = T2.id WHERE T1.superhero_name = 'Blackwulf'
49f9eeb5-fb6c-4255-885f-5030c7e32954	superhero	List the power of superheroes with height greater than 80% of the average height of all superheroes.	SELECT T3.power_name FROM superhero AS T1 INNER JOIN hero_power AS T2 ON T1.id = T2.hero_id INNER JOIN superpower AS T3 ON T2.power_id = T3.id WHERE T1.height_cm * 100 > ( SELECT AVG(height_cm) FROM superhero ) * 80
5c44aec0-03af-4c55-bc6b-dfb187126919	formula_1	Please list the reference names of the drivers who are eliminated in the first period in race number 20.	SELECT T2.driverRef FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 20 ORDER BY T1.q1 DESC LIMIT 5
d0ccc795-c5c5-4322-ad1f-5ce164a37809	formula_1	What is the surname of the driver with the best lap time in race number 19 in the second qualifying period?	SELECT T2.surname FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 19 ORDER BY T1.q2 ASC LIMIT 1
62611ff1-9315-42e7-887b-3b37b3a02487	formula_1	Please list the year during which the race is held on circuits in Shanghai.	SELECT T2.year FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.location = 'Shanghai'
164d9bd2-0a76-4654-84b4-036568af1d04	formula_1	Where can the introduction of the races held on Circuit de Barcelona-Catalunya be found?	SELECT DISTINCT T1.url FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Circuit de Barcelona-Catalunya'
0df400b1-830d-4e42-8ea3-1d5a1b3d70f7	formula_1	Please give the name of the race held on the circuits in Germany.	SELECT DISTINCT T2.name FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.country = 'Germany'
ad36592c-d0d7-47f0-853a-51b0c3c56b53	formula_1	Please list the positions of the circuits built by the constructor Renault.	SELECT DISTINCT T1.position FROM constructorStandings AS T1 INNER JOIN constructors AS T2 ON T2.constructorId = T1.constructorId WHERE T2.name = 'Renault'
3a2ee230-25f3-459f-a725-9ad0aaae165b	formula_1	How many races in the year 2010 are held on grand prixs outside Asia and Europe?	SELECT COUNT(T3.raceId) FROM circuits AS T1 INNER JOIN races AS T3 ON T3.circuitID = T1.circuitId WHERE T1.country NOT IN ( 'Bahrain', 'China', 'Singapore', 'Japan', 'Korea', 'Turkey', 'UAE', 'Malaysia', 'Spain', 'Monaco', 'Azerbaijan', 'Austria', 'Belgium', 'France', 'Germany', 'Hungary', 'Italy', 'UK' ) AND T3.year = 2010
13fbd212-1369-46bf-8fe5-48741e08adb6	formula_1	Please give the names of the races held on the circuits in Spain.	SELECT DISTINCT T2.name FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.country = 'Spain'
554abed1-94e4-4853-828f-6d493761688a	formula_1	What is the coordinates location of the circuits for Australian grand prix?	SELECT DISTINCT T1.lat, T1.lng FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.name = 'Australian Grand Prix'
b54db4f0-4d55-4a70-badf-693149836d9b	formula_1	Where can I find the information about the races held on Sepang International Circuit?	SELECT DISTINCT T1.url FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Sepang International Circuit'
20c45855-fbe8-4ae9-8704-5f92062aeaf9	formula_1	Please list the time of the races held on Sepang International Circuit.	SELECT DISTINCT T2.time FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Sepang International Circuit'
48679bf0-01c1-4c00-8160-7c85f5716fc0	formula_1	Give the coordinate position for Abu Dhabi Grand Prix.	SELECT DISTINCT T1.lat, T1.lng FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.name = 'Abu Dhabi Grand Prix'
fee59676-ce50-472b-bc99-073f36cb397c	formula_1	Which country is the constructor which got 1 point in the race No. 24 from?	SELECT T2.nationality FROM constructorResults AS T1 INNER JOIN constructors AS T2 ON T2.constructorId = T1.constructorId WHERE T1.raceId = 24 AND T1.points = 1
78301dd6-6ffe-4751-8cbe-9e38c55d4f24	formula_1	What's Bruno Senna's Q1 result in the qualifying race No. 354?	SELECT T1.q1 FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 354 AND T2.forename = 'Bruno' AND T2.surname = 'Senna'
dab6744a-0204-4f3a-98c9-1f773e98e611	formula_1	For the driver who had the Q2 time as 0:01:40 in the qualifying race No. 355, what is his nationality?	SELECT DISTINCT T2.nationality FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 355 AND T1.q2 LIKE '1:40%'
d59e1dd5-b7d0-462a-9e97-19f65a2b06ad	formula_1	What is his number of the driver who finished 0:01:54 in the Q3 of qualifying race No.903?	SELECT T2.number FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 903 AND T1.q3 LIKE '1:54%'
4dc3b625-50a5-42b1-aa70-b23f476ba424	formula_1	For the Bahrain Grand Prix in 2007, how many drivers not finished the game?	SELECT COUNT(T3.driverId) FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T1.year = 2007 AND T1.name = 'Bahrain Grand Prix' AND T2.time IS NULL
4a820bd0-14da-4df4-bca0-29cd4b5f153f	formula_1	Show me the season page of year when the race No. 901 took place.	SELECT T2.url FROM races AS T1 INNER JOIN seasons AS T2 ON T2.year = T1.year WHERE T1.raceId = 901
aba51459-d31b-40ec-a008-91169581d31c	formula_1	For the race happened on 2015/11/29, how many drivers finished the game?	SELECT COUNT(T2.driverId) FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId WHERE T1.date = '2015-11-29' AND T2.time IS NOT NULL
8fb98934-9177-4aaf-813e-431ef2326020	formula_1	For all the drivers who finished the game in race No. 592, who is the oldest?	SELECT T1.forename, T1.surname FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId WHERE T2.raceId = 592 AND T2.time IS NOT NULL AND T1.dob IS NOT NULL ORDER BY T1.dob ASC LIMIT 1
991f8568-7f2c-4ebe-a902-df5409baebb7	formula_1	Who was the player that got the lap time of 0:01:27 in the race No. 161? Show his introduction website.	SELECT DISTINCT T2.forename, T2.surname, T2.url FROM lapTimes AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 161 AND T1.time LIKE '1:27%'
a7991216-82a5-4147-b4fb-d2df93383768	formula_1	For the driver who set the fastest lap speed in race No.933, where does he come from?	SELECT T1.nationality FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId WHERE T2.raceId = 933 AND T2.fastestLapTime IS NOT NULL ORDER BY T2.fastestLapSpeed DESC LIMIT 1
37ef89ce-866b-4391-bd01-931386457f17	formula_1	Where is Malaysian Grand Prix held? Give the location coordinates.	SELECT DISTINCT T1.lat, T1.lng FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.name = 'Malaysian Grand Prix'
79fcf768-d25d-40a7-b43f-09b9bbecee8d	formula_1	For the constructor which got the highest point in the race No. 9 , what is its introduction website?	SELECT T2.url FROM constructorResults AS T1 INNER JOIN constructors AS T2 ON T2.constructorId = T1.constructorId WHERE T1.raceId = 9 ORDER BY T1.points DESC LIMIT 1
e18ecd67-0703-4717-8f43-43fbe24ce5de	formula_1	What's Lucas di Grassi's Q1 result in the race No. 345?	SELECT T1.q1 FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 345 AND T2.forename = 'Lucas' AND T2.surname = 'di Grassi'
6a2b982c-91c4-4c69-bb18-4c872bb24719	formula_1	For the driver who had the Q2 time as 0:01:15 in race No. 347, where is he from?	SELECT DISTINCT T2.nationality FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 347 AND T1.q2 LIKE '1:15%'
9eed0039-19a1-4290-98b3-aebd981caf68	formula_1	In the race No. 45, for the driver who had the Q3 time as 0:01:33, what is his abbreviated code?	SELECT T2.code FROM qualifying AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 45 AND T1.q3 LIKE '1:33%'
6047c27d-b90f-44b6-8bc1-0ae86416c844	formula_1	What is the actual finish time for Bruce McLaren in the race No.743?	SELECT T2.time FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId WHERE T2.raceId = 743 AND T1.forename = 'Bruce' AND T1.surname = 'McLaren'
64ad9369-1bc8-403d-954c-4839312546d6	formula_1	Who finished second in the San Marino Grand Prix in 2006?	SELECT T3.forename, T3.surname FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T1.year = 2006 AND T1.name = 'San Marino Grand Prix' AND T2.position = 2
440acc7f-6e82-4c36-9850-2721915592a5	formula_1	Show me the season page of year when the race No. 901 took place.	SELECT T2.url FROM races AS T1 INNER JOIN seasons AS T2 ON T2.year = T1.year WHERE T1.raceId = 901
55d78cf1-71c3-410c-a4bb-4fdc0bf8ef84	formula_1	For the race happened in 2015/11/29, how many drivers did not finish the game?	SELECT COUNT(T2.driverId) FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId WHERE T1.date = '2015-11-29' AND T2.time IS NULL
ebe66861-27c8-415c-b2e1-3cb9d0768efb	formula_1	For all the drivers who finished the game in race No. 872, who is the youngest?	SELECT T1.forename, T1.surname FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId WHERE T2.raceId = 872 AND T2.time IS NOT NULL ORDER BY T1.dob DESC LIMIT 1
e18aee58-2bee-4c33-9d39-bbc74418f29a	formula_1	Who was the driver that got the best lap time in the race No. 348? Give his full name.	SELECT T2.forename, T2.surname FROM lapTimes AS T1 INNER JOIN drivers AS T2 ON T2.driverId = T1.driverId WHERE T1.raceId = 348 ORDER BY T1.time ASC LIMIT 1
9750be3e-9454-4226-ab28-5abad341d99e	formula_1	For the driver who set the fastest lap speed, what is his nationality?	SELECT T1.nationality FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId ORDER BY T2.fastestLapSpeed DESC LIMIT 1
b790f0fc-73ca-49e5-9ce5-8d5ceded7c7d	formula_1	Paul di Resta was in the No. 853 race, what percent faster did he finish in the 853rd race than the next race for the fastest lap speed?	SELECT (SUM(IIF(T2.raceId = 853, T2.fastestLapSpeed, 0)) - SUM(IIF(T2.raceId = 854, T2.fastestLapSpeed, 0))) * 100 / SUM(IIF(T2.raceId = 853, T2.fastestLapSpeed, 0)) FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId WHERE T1.forename = 'Paul' AND T1.surname = 'di Resta'
331a4d70-e0bf-4bbf-9ed8-b409c2bcd551	formula_1	For the drivers who took part in the race in 1983/7/16, what's their race completion rate?	SELECT CAST(COUNT(CASE WHEN T2.time IS NOT NULL THEN T2.driverId END) AS REAL) * 100 / COUNT(T2.driverId) FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId WHERE T1.date = '1983-07-16'
bb1f1f1d-3741-4dd8-9775-4a04f4863f92	formula_1	Which year was the first Singapore Grand Prix?	SELECT year FROM races WHERE name = 'Singapore Grand Prix' ORDER BY year ASC LIMIT 1
4993f42d-9610-4974-8131-8c663eae4c66	formula_1	How many races were there in 2005? Name all the races in descending order.	SELECT name FROM races WHERE year = 2005 ORDER BY name DESC
da1ba750-7ef6-45a6-89c4-4965aee5e3b2	formula_1	List the names of all races that occurred in the earliest recorded year and month.	SELECT name FROM races WHERE STRFTIME('%Y', date) = ( SELECT STRFTIME('%Y', date) FROM races ORDER BY date ASC LIMIT 1 ) AND STRFTIME('%m', date) = ( SELECT STRFTIME('%m', date) FROM races ORDER BY date ASC LIMIT 1 )
004f4234-d92e-4563-9f7e-96f6b000c1b4	formula_1	State the name and date of the last round of race in year 1999.	SELECT name, date FROM races WHERE year = 1999 ORDER BY round DESC LIMIT 1
02386f58-db95-426e-b5a1-8a836690d6a8	formula_1	Which year has the most number of races?	SELECT year FROM races GROUP BY year ORDER BY COUNT(round) DESC LIMIT 1
abe7f369-f29a-47e8-93de-4ebb3b5847de	formula_1	Name the races in year 2017 that are not hosted in year 2000.	SELECT name FROM races WHERE year = 2017 AND name NOT IN ( SELECT name FROM races WHERE year = 2000 )
80b18656-0b99-47da-97e1-90877dd4fb2b	formula_1	In which country was the first European Grand Prix hosted? Name the circuit and location.	SELECT T1.country, T1.location FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.name = 'European Grand Prix' ORDER BY T2.year ASC LIMIT 1
e5c063e5-6410-4c83-a962-71bb8d088424	formula_1	When was the last f1 season whereby Brands Hatch hosted the British Grand Prix?	SELECT T2.date FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Brands Hatch' AND T2.name = 'British Grand Prix' ORDER BY T2.year DESC LIMIT 1
fc1e9a45-3e91-427d-89e5-6e0afab245c4	formula_1	How many seasons has Silverstone Circuit hosted the United Kindom grand prix?	SELECT COUNT(T2.circuitid) FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Silverstone Circuit' AND T2.name = 'British Grand Prix'
347a1f54-7312-4cf3-9c9e-21cab2e7fad6	formula_1	Name all drivers in the 2010 Singapore Grand Prix order by their position stands.	SELECT T3.forename, T3.surname FROM races AS T1 INNER JOIN driverStandings AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T1.name = 'Singapore Grand Prix' AND T1.year = 2010 ORDER BY T2.position ASC
0ba0e22f-c117-4e68-9ab2-7f10adeea6fe	formula_1	State the driver with the most points scored. Find his full name with that points.	SELECT T3.forename, T3.surname, T2.points FROM races AS T1 INNER JOIN driverStandings AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId ORDER BY T2.points DESC LIMIT 1
01951feb-ce59-46ce-898c-0dbe058325b7	formula_1	Name the top 3 drivers and the points they scored in the 2017 Chinese Grand Prix.	SELECT T3.forename, T3.surname, T2.points FROM races AS T1 INNER JOIN driverStandings AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T1.name = 'Chinese Grand Prix' AND T1.year = 2017 ORDER BY T2.points DESC LIMIT 3
291e341e-298c-4852-a473-d228dea44694	formula_1	What is the best lap time recorded? List the driver and race with such recorded lap time.	SELECT T2.milliseconds, T1.forename, T1.surname, T3.name FROM drivers AS T1 INNER JOIN lapTimes AS T2 ON T1.driverId = T2.driverId INNER JOIN races AS T3 ON T2.raceId = T3.raceId ORDER BY T2.milliseconds ASC LIMIT 1
bf0c0d94-b7de-4c06-9dd0-88c7544a03aa	formula_1	What is the average lap time for Lewis Hamilton in the 2009 Malaysian Grand Prix?	SELECT AVG(T2.milliseconds) FROM races AS T1 INNER JOIN lapTimes AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.forename = 'Lewis' AND T3.surname = 'Hamilton' AND T1.year = 2009 AND T1.name = 'Malaysian Grand Prix'
55243bed-3d8b-4f7a-8c66-01b1751223df	formula_1	Calculate the percentage whereby Hamilton was not at the 1st track of the the f1 circuit since 2010.	SELECT CAST(COUNT(CASE WHEN T2.position <> 1 THEN T2.position END) AS REAL) * 100 / COUNT(T2.driverStandingsId) FROM races AS T1 INNER JOIN driverStandings AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.surname = 'Hamilton' AND T1.year >= 2010
55d33a55-c223-460e-9a45-37e60cd65528	formula_1	Name the driver with the most winning. Mention his nationality and what is his maximum point scores.	SELECT T1.forename, T1.surname, T1.nationality, MAX(T2.points) FROM drivers AS T1 INNER JOIN driverStandings AS T2 ON T2.driverId = T1.driverId WHERE T2.wins >= 1 GROUP BY T1.forename, T1.surname, T1.nationality ORDER BY COUNT(T2.wins) DESC LIMIT 1
7f61edb4-39b1-40ea-b85d-9ba8dfb3128b	formula_1	How old is the youngest Japanese driver? What is his name?	SELECT STRFTIME('%Y', CURRENT_TIMESTAMP) - STRFTIME('%Y', dob), forename , surname FROM drivers WHERE nationality = 'Japanese' ORDER BY dob DESC LIMIT 1
2cbf4fee-8977-4522-b988-f726c0fdc834	formula_1	List circuits which host 4 f1 races from year 1990 to 2000.	SELECT DISTINCT T1.name FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE STRFTIME('%Y', T2.date) BETWEEN '1990' AND '2000' GROUP BY T1.name HAVING COUNT(T2.raceId) = 4
62f4d541-359b-4ad4-8e6d-d41d6e889f09	formula_1	List circuits in USA which hosted f1 races in 2006. State the name and location of circuit and the name of the race it hosted.	SELECT T1.name, T1.location, T2.name FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.country = 'USA' AND T2.year = 2006
57026af3-3a17-469e-b531-43729cf118c0	formula_1	Name the races along with its circuit name and location for f1 races hosted in September 2005.	SELECT DISTINCT T2.name, T1.name, T1.location FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.year = 2005 AND STRFTIME('%m', T2.date) = '09'
2c3d6117-7f81-4223-a54b-aac4f1331c2f	formula_1	Which race was Alex Yoong in when he was in track number less than 20?	SELECT T1.name FROM races AS T1 INNER JOIN driverStandings AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.forename = 'Alex' AND T3.surname = 'Yoong' AND T2.position < 20
f9a882ea-79b3-4f96-8445-3464de04649e	formula_1	How many times did Michael Schumacher won from races hosted in Sepang International Circuit?	SELECT SUM(T2.wins) FROM drivers AS T1 INNER JOIN driverStandings AS T2 ON T2.driverId = T1.driverId INNER JOIN races AS T3 ON T3.raceId = T2.raceId INNER JOIN circuits AS T4 ON T4.circuitId = T3.circuitId WHERE T1.forename = 'Michael' AND T1.surname = 'Schumacher' AND T4.name = 'Sepang International Circuit'
0841fcf2-1e3e-42d4-8605-25fa61234b0c	formula_1	State the race and year of race in which Michael Schumacher had his fastest lap.	SELECT T1.name, T1.year FROM races AS T1 INNER JOIN lapTimes AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.forename = 'Michael' AND T3.surname = 'Schumacher' ORDER BY T2.milliseconds ASC LIMIT 1
9f051e40-2f18-4cf7-8be1-8aa89034b258	formula_1	What is Eddie Irvine's average points scored in year 2000?	SELECT AVG(T2.points) FROM drivers AS T1 INNER JOIN driverStandings AS T2 ON T2.driverId = T1.driverId INNER JOIN races AS T3 ON T3.raceId = T2.raceId WHERE T1.forename = 'Eddie' AND T1.surname = 'Irvine' AND T3.year = 2000
8f1aa36d-50f4-49fc-b13e-63886eb8535e	formula_1	Which was Lewis Hamilton first race? What was his points recorded for his first race event?	SELECT T1.name, T2.points FROM races AS T1 INNER JOIN driverStandings AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.forename = 'Lewis' AND T3.surname = 'Hamilton' ORDER BY T1.year ASC LIMIT 1
befb39e1-e867-4433-9f41-715b8601c584	formula_1	List all races in 2017 and the hosting country order by date of the event.	SELECT DISTINCT T2.name, T1.country FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.year = 2017 ORDER BY T2.date ASC
778439e3-4069-49c4-864d-eb6d9602a0a4	formula_1	What is the most laps f1 races had? Name the race, year and circuit location where the races with most laps was hosted.	SELECT T3.lap, T2.name, T2.year, T1.location FROM circuits AS T1 INNER JOIN races AS T2 ON T1.circuitId = T2.circuitId INNER JOIN lapTimes AS T3 ON T3.raceId = T2.raceId ORDER BY T3.lap DESC LIMIT 1
bdcae3af-0888-421d-9285-92514b196daf	formula_1	Among all European Grand Prix races, what is the percentage of the races were hosted in Germany?	SELECT CAST(COUNT(CASE WHEN T1.country = 'Germany' THEN T2.circuitID END) AS REAL) * 100 / COUNT(T2.circuitId) FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.name = 'European Grand Prix'
a67580f9-97db-426a-8ace-81dc9786e7e0	formula_1	What's the location coordinates of Silverstone Circuit?	SELECT lat, lng FROM circuits WHERE name = 'Silverstone Circuit'
3d9a90c5-68bc-4cc7-92fb-472ef131806d	formula_1	Which of these circuits is located at a higher latitude, Silverstone Circuit, Hockenheimring or Hungaroring?	SELECT name FROM circuits WHERE name IN ('Silverstone Circuit', 'Hockenheimring', 'Hungaroring') ORDER BY lat DESC LIMIT 1
8cdffe80-24c6-4d11-b45a-8f46e7e6c197	formula_1	What's the reference name of Marina Bay Street Circuit?	SELECT circuitRef FROM circuits WHERE name = 'Marina Bay Street Circuit'
2b13ed27-d717-40d4-b726-dee4bc50a8cc	formula_1	In which country can I find the circuit with the highest altitude?	SELECT country FROM circuits ORDER BY alt DESC LIMIT 1
336bf90e-2380-47b6-a1ef-b7b151a144ba	formula_1	How many drivers don't have a code?	SELECT COUNT(driverId) - COUNT(CASE WHEN code IS NOT NULL THEN code END) FROM drivers
efeba9b7-60b5-4f63-9f16-a5578ba6b579	formula_1	Which country is the oldest driver from?	SELECT nationality FROM drivers WHERE dob IS NOT NULL ORDER BY dob ASC LIMIT 1
ea7644a8-c552-4c1b-aa7a-2a94b73d1a2f	formula_1	Please list the surnames of all the Italian drivers.	SELECT surname FROM drivers WHERE nationality = 'Italian'
c5735d08-b95d-4cfa-9ee7-4f691dd71a0f	formula_1	Which website should I go to if I want to know more about Anthony Davidson?	SELECT url FROM drivers WHERE forename = 'Anthony' AND surname = 'Davidson'
0959a680-9969-4ba8-ac91-341f7de64541	formula_1	What's Lewis Hamilton's reference name?	SELECT driverRef FROM drivers WHERE forename = 'Lewis' AND surname = 'Hamilton'
1e3c9d83-f0ad-4823-bc14-b90aeb80c568	formula_1	Which circuit did the 2009 Spanish Grand Prix use?	SELECT T1.name FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.year = 2009 AND T2.name = 'Spanish Grand Prix'
e904fe94-5ab9-4ea1-b203-47bc6152c383	formula_1	Please list all the years that Silverstone Circuit was used in a Formula_1 race.	SELECT DISTINCT T2.year FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Silverstone Circuit'
4323b12f-3c38-4e71-b590-18478317fa92	formula_1	Please give more information about the Formula_1 races that used the Silverstone Circuit.	SELECT DISTINCT T1.url FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Silverstone Circuit'
4bfda500-a8bd-494b-8c42-d0b4514d1619	formula_1	What time did the the 2010's Formula_1 race took place on the Abu Dhabi Circuit?	SELECT T2.date, T2.time FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.year = 2010 AND T2.name = 'Abu Dhabi Grand Prix'
da9f7672-9da4-485b-97ba-4ce8284e1741	formula_1	How many Formula_1 races took place on the circuits in Italy?	SELECT COUNT(T2.circuitId) FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.country = 'Italy'
c5350c41-407b-42af-bca4-8215ca29d833	formula_1	Please list the exact dates on which a Formula_1 race took place on the Barcelona-Catalunya circuit.	SELECT T2.date FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T1.name = 'Circuit de Barcelona-Catalunya'
75e171fd-0d60-46fa-97e9-623d73888d4f	formula_1	Please give the link of the website that shows more information about the circuits the Spanish Grand Prix used in 2009.	SELECT T1.url FROM circuits AS T1 INNER JOIN races AS T2 ON T2.circuitID = T1.circuitId WHERE T2.year = 2009 AND T2.name = 'Spanish Grand Prix'
aa359cd3-22c5-479d-b066-5a51796a11c7	formula_1	What's the fastest lap time ever in a race for Lewis Hamilton?	SELECT T2.fastestLapTime FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId WHERE T1.forename = 'Lewis' AND T1.surname = 'Hamilton' AND T2.fastestLapTime IS NOT NULL ORDER BY T2.fastestLapTime ASC LIMIT 1
94155be7-c79f-41fb-9fff-14eb8ed10479	formula_1	Which driver created the fastest lap speed in a Formula_1 race? Please give both his forename and surname.	SELECT T1.forename, T1.surname FROM drivers AS T1 INNER JOIN results AS T2 ON T2.driverId = T1.driverId WHERE T2.fastestLapTime IS NOT NULL ORDER BY T2.fastestLapSpeed DESC LIMIT 1
6d6334ab-fe69-4e0f-a4e8-be7222fe81d1	formula_1	Which driver ranked the first in the Canadian Grand Prix in 2007? Please give his reference name.	SELECT T3.forename, T3.surname, T3.driverRef FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T1.name = 'Canadian Grand Prix' AND T2.rank = 1 AND T1.year = 2007
82d3a439-eb4e-45b8-9a7e-2cd14a1af5c4	formula_1	Please list the Formula_1 races that Lewis Hamilton participated.	SELECT T1.name FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.forename = 'Lewis' AND T3.surname = 'Hamilton'
520f8396-606d-4fc7-bedc-021c42de273c	formula_1	In which Formula_1 race did Lewis Hamilton rank the highest?	SELECT name FROM races WHERE raceId IN ( SELECT raceId FROM results WHERE rank = 1 AND driverId = ( SELECT driverId FROM drivers WHERE forename = 'Lewis' AND surname = 'Hamilton' ) )
83c4e406-7877-4973-9087-4045cd075446	formula_1	What was the fastest lap speed among all drivers in the 2009 Spanish Grand Prix?	SELECT T2.fastestLapSpeed FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId WHERE T1.name = 'Spanish Grand Prix' AND T1.year = 2009 AND T2.fastestLapSpeed IS NOT NULL ORDER BY T2.fastestLapSpeed DESC LIMIT 1
428f51b5-3f27-4de4-8167-6481831966ec	formula_1	In which years did Lewis Hamilton participate in a Formula_1 race?	SELECT DISTINCT T1.year FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.forename = 'Lewis' AND T3.surname = 'Hamilton'
7dd6a1ee-709a-4232-9569-9002568f3e2f	formula_1	What was Lewis Hamilton's final rank in the 2008 Chinese Grand Prix?	SELECT T2.positionOrder FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T3.forename = 'Lewis' AND T3.surname = 'Hamilton' AND T1.name = 'Chinese Grand Prix' AND T1.year = 2008
c0bed35c-42f3-4584-8046-001cde33d4f9	formula_1	Which driver was in the no. 4 grid formation when starting the race in 1989's Australian Grand Prix? Please give his forename and surname.	SELECT T3.forename, T3.surname FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId INNER JOIN drivers AS T3 ON T3.driverId = T2.driverId WHERE T2.grid = 4 AND T1.name = 'Australian Grand Prix' AND T1.year = 1989
d87e823d-1789-4207-ab97-e220cb76c89c	formula_1	How many drivers managed to finish the race in the 2008 Australian Grand Prix?	SELECT COUNT(T2.driverId) FROM races AS T1 INNER JOIN results AS T2 ON T2.raceId = T1.raceId WHERE T1.name = 'Australian Grand Prix' AND T1.year = 2008 AND T2.time IS NOT NULL
8d5babf0-7bae-4b64-884c-ce615bac6e4d	formula_1	Which was the fastest lap for Lewis Hamilton in the 2008 Australian Grand Prix?	SELECT T1.fastestLap FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN drivers AS T3 on T1.driverId = T3.driverId WHERE T2.name = 'Australian Grand Prix' AND T2.year = 2008 AND T3.forename = 'Lewis' AND T3.surname = 'Hamilton'
d48681a9-9a68-48e3-bb29-8982f39eb200	formula_1	What's the finish time for the driver who ranked second in 2008's AustChineseralian Grand Prix?	SELECT T1.time FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T1.rank = 2 AND T2.name = 'Chinese Grand Prix' AND T2.year = 2008
f95f13ee-da35-4529-8d12-c70a06682038	formula_1	Who was the champion of 2008's Australian Grand Prix and where can I know more about him?	SELECT T1.forename, T1.surname, T1.url FROM drivers AS T1 INNER JOIN results AS T2 ON T1.driverId = T2.driverId INNER JOIN races AS T3 ON T3.raceId = T2.raceId WHERE T3.name = 'Australian Grand Prix' AND T2.time LIKE '_:%:__.___' AND T3.year = 2008
f718572b-38fc-4f3f-99b4-a318634cc5db	formula_1	How many drivers from the UN participated in the 2008 Australian Grand Prix?	SELECT COUNT(*) FROM drivers AS T1 INNER JOIN results AS T2 ON T1.driverId = T2.driverId INNER JOIN races AS T3 ON T3.raceId = T2.raceId WHERE T3.name = 'Australian Grand Prix' AND T1.nationality = 'British' AND T3.year = 2008
d6497db5-2f75-41d2-b40f-18817fc35cbc	formula_1	Among the drivers that finished the race in the 2008 Chinese Grand Prix, how many of them have participated in Formula_1 races?	SELECT COUNT(*) FROM ( SELECT T1.driverId FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T2.name = 'Chinese Grand Prix' AND T2.year = 2008 AND T1.time IS NOT NULL GROUP BY T1.driverId HAVING COUNT(T2.raceId) > 0 )
65ed31ef-ac81-4ea9-90fa-def69046911d	formula_1	How many points did Lewis Hamilton get in total in all the Formula_1 races he participated?	SELECT SUM(T2.points) FROM drivers AS T1 INNER JOIN results AS T2 ON T1.driverId = T2.driverId WHERE T1.forename = 'Lewis' AND T1.surname = 'Hamilton'
3513c0d6-1be3-4bd7-b341-69b70756d722	formula_1	What is the average fastest lap time in seconds for Lewis Hamilton in all the Formula_1 races?	SELECT AVG(CAST(SUBSTR(T2.fastestLapTime, 1, INSTR(T2.fastestLapTime, ':') - 1) AS INTEGER) * 60 + CAST(SUBSTR(T2.fastestLapTime, INSTR(T2.fastestLapTime, ':') + 1) AS REAL)) FROM drivers AS T1 INNER JOIN results AS T2 ON T1.driverId = T2.driverId WHERE T1.surname = 'Hamilton' AND T1.forename = 'Lewis'
74f39167-574b-43bc-a336-7bfe1d10c5a6	formula_1	What is the rate of drivers completing all the laps in the 2008 Australian Grand Prix?	SELECT CAST(SUM(IIF(T1.time IS NOT NULL, 1, 0)) AS REAL) * 100 / COUNT(T1.resultId) FROM results AS T1 INNER JOIN races AS T2 ON T1.raceId = T2.raceId WHERE T2.name = 'Australian Grand Prix' AND T2.year = 2008
b6301927-2a3a-4506-8b0f-a5d3b0101e28	formula_1	How many British drivers who were born in 1980?	SELECT COUNT(driverId) FROM drivers WHERE nationality = 'British' AND STRFTIME('%Y', dob) = '1980'
8cec72d5-5618-44e1-96c9-3b9a9d219412	formula_1	List out top 3 German drivers who were born from 1980-1990 and have the earliest lap time.	SELECT T2.driverId FROM pitStops AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.nationality = 'German' AND STRFTIME('%Y', T2.dob) BETWEEN '1980' AND '1990' ORDER BY T1.time LIMIT 3
00201f74-7bf2-4c2f-9bfd-d1d7163a7185	formula_1	How much faster in percentage is the champion than the driver who finished the race last in the 2008 Australian Grand Prix?	WITH time_in_seconds AS ( SELECT T1.positionOrder, CASE WHEN T1.positionOrder = 1 THEN (CAST(SUBSTR(T1.time, 1, 1) AS REAL) * 3600) + (CAST(SUBSTR(T1.time, 3, 2) AS REAL) * 60) + CAST(SUBSTR(T1.time, 6) AS REAL) ELSE CAST(SUBSTR(T1.time, 2) AS REAL) END AS time_seconds FROM results AS T1 INNER JOIN races AS T2 ON T1.raceId = T2.raceId WHERE T2.name = 'Australian Grand Prix' AND T1.time IS NOT NULL AND T2.year = 2008 ), champion_time AS ( SELECT time_seconds FROM time_in_seconds WHERE positionOrder = 1), last_driver_incremental AS ( SELECT time_seconds FROM time_in_seconds WHERE positionOrder = (SELECT MAX(positionOrder) FROM time_in_seconds) ) SELECT (CAST((SELECT time_seconds FROM last_driver_incremental) AS REAL) * 100) / (SELECT time_seconds + (SELECT time_seconds FROM last_driver_incremental) FROM champion_time)
91f56295-3041-4356-a2aa-e8db6987e064	formula_1	How many circuits are there in Adelaide, Australia?	SELECT COUNT(circuitId) FROM circuits WHERE location = 'Adelaide' AND country = 'Australia'
17b58837-10c3-4a2b-81b7-b4b030709125	formula_1	Please list the location coordinates of the US circuits.	SELECT lat, lng FROM circuits WHERE country = 'USA'
212c77ad-f608-4c28-b794-410d1c749c83	formula_1	How many British drivers were born after 1980?	SELECT COUNT(driverId) FROM drivers WHERE nationality = 'British' AND STRFTIME('%Y', dob) > '1980'
044d3e2f-d7b9-416f-8e40-6857a62c3b57	formula_1	What are the maximum points of British constructors?	SELECT MAX(T1.points) FROM constructorStandings AS T1 INNER JOIN constructors AS T2 on T1.constructorId = T2.constructorId WHERE T2.nationality = 'British'
332ebf79-fbe0-4751-a7de-a75d743bb2dc	formula_1	Which constructor has the highest point?	SELECT T2.name FROM constructorStandings AS T1 INNER JOIN constructors AS T2 on T1.constructorId = T2.constructorId ORDER BY T1.points DESC LIMIT 1
3f9c4325-97d8-44ee-934f-2eb9126ee30b	formula_1	Please list the constructor names with 0 points at race 291.	SELECT T2.name FROM constructorStandings AS T1 INNER JOIN constructors AS T2 on T1.constructorId = T2.constructorId WHERE T1.points = 0 AND T1.raceId = 291
e9cc2d2d-0682-43f4-9de6-e4b9c036be2f	formula_1	How many Japanese constructors have 0 points in 2 races?	SELECT COUNT(T1.raceId) FROM constructorStandings AS T1 INNER JOIN constructors AS T2 on T1.constructorId = T2.constructorId WHERE T1.points = 0 AND T2.nationality = 'Japanese' GROUP BY T1.constructorId HAVING COUNT(raceId) = 2
eed89c8b-aa05-4b8a-b4a6-09b7ba473888	formula_1	Which constructors have been ranked 1?	SELECT DISTINCT T2.name FROM results AS T1 INNER JOIN constructors AS T2 on T1.constructorId = T2.constructorId WHERE T1.rank = 1
b9c18d95-fe4f-4f07-a41e-16042964f252	formula_1	How many French constructors have a lap number of over 50?	SELECT COUNT(DISTINCT T2.constructorId) FROM results AS T1 INNER JOIN constructors AS T2 on T1.constructorId = T2.constructorId WHERE T1.laps > 50 AND T2.nationality = 'French'
2b857bb4-4c88-4d71-8662-7b7a6d39c5c6	formula_1	Please calculate the race completion percentage of Japanese drivers from 2007 to 2009.	SELECT CAST(SUM(IIF(T1.time IS NOT NULL, 1, 0)) AS REAL) * 100 / COUNT(T1.raceId) FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN drivers AS T3 on T1.driverId = T3.driverId WHERE T3.nationality = 'Japanese' AND T2.year BETWEEN 2007 AND 2009
3d55c858-240f-491e-9c35-770ec4bbaee4	formula_1	What is the average time in seconds of champion for each year, before year 1975?	WITH time_in_seconds AS ( SELECT T2.year, T2.raceId, T1.positionOrder, CASE WHEN T1.positionOrder = 1 THEN (CAST(SUBSTR(T1.time, 1, 1) AS REAL) * 3600) + (CAST(SUBSTR(T1.time, 3, 2) AS REAL) * 60) + CAST(SUBSTR(T1.time, 6,2) AS REAL )   + CAST(SUBSTR(T1.time, 9) AS REAL)/1000 ELSE 0 END AS time_seconds FROM results AS T1 INNER JOIN races AS T2 ON T1.raceId = T2.raceId WHERE T1.time IS NOT NULL ), champion_time AS ( SELECT year, raceId, time_seconds FROM time_in_seconds WHERE positionOrder = 1 ) SELECT year, AVG(time_seconds) FROM champion_time WHERE year < 1975 GROUP BY year HAVING AVG(time_seconds) IS NOT NULL
8de3ae7d-18c0-472f-9185-c88184f16356	formula_1	Which drivers born after 1975 have been ranked 2? Please give their forenames and surnames.	SELECT T2.forename, T2.surname FROM results AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE STRFTIME('%Y', T2.dob) > '1975' AND T1.rank = 2
c8f4b16b-6278-4fa4-b430-c1a523473153	formula_1	How many Italian drivers haven't finished the race?	SELECT COUNT(T1.driverId) FROM results AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.nationality = 'Italian' AND T1.time IS NULL
24098bd3-97f7-45ee-b3f4-44860c00e7db	formula_1	Which driver has the fastest lap time? Please give their forenames and surnames.	SELECT T2.forename, T2.surname, T1.fastestLapTime FROM results AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T1.fastestLapTime IS NOT NULL ORDER BY T1.fastestLapTime ASC LIMIT 1
b20363cb-2ff2-4181-8dd9-bca9683daa58	formula_1	What is the fastest lap number of the champion in 2009?	SELECT T1.fastestLap FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T2.year = 2009 AND T1.time LIKE '_:%:__.___'
8bf1ffe7-ef92-409e-8e16-c85ec96fa863	formula_1	What is the average of fastest lap speed in the 2009 Spanish Grand Prix race?	SELECT AVG(T1.fastestLapSpeed) FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T2.year = 2009 AND T2.name = 'Spanish Grand Prix'
cab597dd-8d3b-4313-b677-7cd92d5d8d91	formula_1	Which race has the shortest actual finishing time? Please give the name and year.	SELECT T1.name, T1.year FROM races AS T1 INNER JOIN results AS T2 on T1.raceId = T2.raceId WHERE T2.milliseconds IS NOT NULL ORDER BY T2.milliseconds LIMIT 1
39f6a5e8-b8b8-49e5-a80c-d19245be9bf1	formula_1	From 2000 to 2005, what percentage of drivers who were born before 1985 and the lap numbers were over 50?	SELECT CAST(SUM(IIF(STRFTIME('%Y', T3.dob) < '1985' AND T1.laps > 50, 1, 0)) AS REAL) * 100 / COUNT(*) FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN drivers AS T3 on T1.driverId = T3.driverId WHERE T2.year BETWEEN 2000 AND 2005
abadd85e-c68b-4eae-a253-e02240340755	formula_1	How many French drivers who obtain the laptime less than 02:00.00?	SELECT COUNT(T1.driverId) FROM drivers AS T1 INNER JOIN lapTimes AS T2 on T1.driverId = T2.driverId WHERE T1.nationality = 'French' AND (CAST(SUBSTR(T2.time, 1, 2) AS INTEGER) * 60 + CAST(SUBSTR(T2.time, 4, 2) AS INTEGER) + CAST(SUBSTR(T2.time, 7, 2) AS REAL) / 1000) < 120
84b8ea5b-f8a2-4f88-b807-c930ef06ef68	formula_1	List out the code for drivers who have nationality in America.	SELECT code FROM drivers WHERE Nationality = 'American'
e7fb24b5-31ee-4b3e-ac49-7891d587d386	formula_1	List out the Id number of races which were hold in 2009.	SELECT raceId FROM races WHERE year = 2009
c5c50467-3acc-4231-95ff-738f14bf1bac	formula_1	How many driver participated in race ID number 18?	SELECT COUNT(driverId) FROM driverStandings WHERE raceId = 18
603bb07c-ca44-477d-8dc3-b769068189b2	formula_1	State code numbers of top 3 yougest drivers. How many Netherlandic drivers among them?	SELECT COUNT(*) FROM ( SELECT T1.nationality FROM drivers AS T1 ORDER BY JULIANDAY(T1.dob) DESC LIMIT 3) AS T3 WHERE T3.nationality = 'Dutch'
980b48f3-852a-4d21-956d-4c84d23df853	formula_1	What is reference name of Robert Kubica?	SELECT driverRef FROM drivers WHERE forename = 'Robert' AND surname = 'Kubica'
285c2d3a-db5e-4562-8e4c-00ddb1e7020b	formula_1	Please state the reference name of the oldest German driver.	SELECT driverRef FROM drivers WHERE nationality = 'German' ORDER BY JULIANDAY(dob) ASC LIMIT 1
e7f8d716-8320-429c-a1c1-f19719f40c35	formula_1	Which drivers who were born in 1971 and has the fastest lap time on the race? Give id and code of these drivers.	SELECT T2.driverId, T2.code FROM results AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE STRFTIME('%Y', T2.dob) = '1971' AND T1.fastestLapTime IS NOT NULL
9d760ac6-62ce-4528-94ce-74590974264b	formula_1	List out top 10 Spanish drivers who were born before 1982 and have the latest lap time.	SELECT T2.driverId FROM pitStops AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.nationality = 'Spanish' AND STRFTIME('%Y', T2.dob) < '1982' ORDER BY T1.time DESC LIMIT 10
0f6cfd9a-ccc6-46ac-b62d-2a0f91c5f0a7	formula_1	State the racing year which has the fastest lap time?	SELECT T2.year FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T1.fastestLapTime IS NOT NULL
22b8fa2a-93c7-48a5-8a3d-e608a1e61b23	formula_1	Which year has the lowest speed of lap time?	SELECT T2.year FROM lapTimes AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId ORDER BY T1.time DESC LIMIT 1
1e103612-af69-4df0-80c5-f992d7cd1e5b	formula_1	List the driver's ID of the top five driver, by descending order, the fastest time during the first lap of the race.	SELECT driverId FROM lapTimes WHERE lap = 1 ORDER BY time LIMIT 5
f5cef9cc-c540-4d8c-b3c8-e01ae472d1b4	formula_1	From race no. 50 to 100, how many finishers have been disqualified?	SELECT SUM(IIF(time IS NOT NULL, 1, 0)) FROM results WHERE statusId = 2 AND raceID < 100 AND raceId > 50
717b6a56-47f5-4918-b8d5-5edf403fd33c	formula_1	How many times the circuits were held in Austria? Please give their location and coordinates.	SELECT DISTINCT location, lat, lng FROM circuits WHERE country = 'Austria'
f0f1d168-6fa4-406d-8e9c-c6dd8d2ade8a	formula_1	What race number has the most finishers?	SELECT raceId FROM results GROUP BY raceId ORDER BY COUNT(time IS NOT NULL) DESC LIMIT 1
d822f06d-576d-409f-a5a3-c34d085b63a6	formula_1	List the reference name of the drivers who passed the second qualifying lap during race no. 23. Indicate their nationality and birthday.	SELECT T2.driverRef, T2.nationality, T2.dob FROM qualifying AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T1.raceId = 23 AND T1.q2 IS NOT NULL
cd8209b3-c0a1-4bf1-b5a2-b63fa9f62b52	formula_1	On what year did the youngest driver had his first qualifying race? Also state the name, date and time of the race.	SELECT T3.year, T3.name, T3.date, T3.time FROM qualifying AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId INNER JOIN races AS T3 on T1.raceId = T3.raceId WHERE T1.driverId = ( SELECT driverId FROM drivers ORDER BY dob DESC LIMIT 1 ) ORDER BY T3.date ASC LIMIT 1
aef62262-a2e1-429e-b149-679521994259	formula_1	How many American drivers have puncture status.	SELECT COUNT(T1.driverId) FROM drivers AS T1 INNER JOIN results AS T2 on T1.driverId = T2.driverId INNER JOIN status AS T3 on T2.statusId = T3.statusId WHERE T3.status = 'Puncture' AND T1.nationality = 'American'
3247dc2d-2710-47b2-a9fa-b61c974958ca	formula_1	Which of the Italian constructor got the highest point to date? Give its introduction website?	SELECT T1.url FROM constructors AS T1 INNER JOIN constructorStandings AS T2 on T1.constructorId = T2.constructorId WHERE T1.nationality = 'Italian' ORDER BY T2.points DESC LIMIT 1
77597b20-5097-48b5-814a-1825954bc138	formula_1	What is the website of the constructor who tallied the most total wins.	SELECT T1.url FROM constructors AS T1 INNER JOIN constructorStandings AS T2 on T1.constructorId = T2.constructorId ORDER BY T2.wins DESC LIMIT 1
d23560a4-6d2b-431d-89e1-a6f83f2b9e5a	formula_1	Among the drivers who participated in the French Grand Prix, who has the slowest time in the 3rd lap.	SELECT T1.driverId FROM lapTimes AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T2.name = 'French Grand Prix' AND T1.lap = 3 ORDER BY T1.time DESC LIMIT 1
1231b870-6dbe-4334-a677-684020d3347e	formula_1	In which race did the fastest 1st lap time was recorded? Please indicate the time in milliseconds.	SELECT T1.milliseconds FROM lapTimes AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T1.lap = 1 ORDER BY T1.time LIMIT 1
0941b9c5-8368-4d4f-862e-1accf953f1d7	formula_1	What is the average fastest lap time of the top 10 drivers in the 2006 United States Grand Prix?	SELECT AVG(T1.fastestLapTime) FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T1.rank < 11 AND T2.year = 2006 AND T2.name = 'United States Grand Prix'
01565ba7-ca79-412f-93a1-10251ae03d89	formula_1	List down top 3 German drivers who has the shortest average pit stop duration and were born between 1980-1985.	SELECT T2.forename, T2.surname FROM pitStops AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.nationality = 'German' AND STRFTIME('%Y', T2.dob) BETWEEN '1980' AND '1985' GROUP BY T2.forename, T2.surname ORDER BY AVG(T1.duration) LIMIT 3
6857b2f6-9e90-4a40-88f1-191b41667cd1	formula_1	Who is the champion of the Canadian Grand Prix in 2008? Indicate his finish time.	SELECT T1.time FROM results AS T1 INNER JOIN races AS T2 ON T1.raceId = T2.raceId WHERE T2.name = 'Canadian Grand Prix' AND T2.year = 2008 AND T1.time LIKE '_:%:__.___'
1d75cd8e-962f-4e44-aa35-bcd03be8b548	formula_1	What is the constructor reference name of the champion in the 2009 Singapore Grand Prix? Please give its website.	SELECT T3.constructorRef, T3.url FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN constructors AS T3 on T1.constructorId = T3.constructorId WHERE T2.name = 'Singapore Grand Prix' AND T2.year = 2009 AND T1.time LIKE '_:%:__.___'
da25e606-0abb-4926-a393-58c17bc73e67	formula_1	What is the full name and date of birth of Austrian drivers born between 1981 and 1991?	SELECT forename, surname, dob FROM drivers WHERE nationality = 'Austrian' AND STRFTIME('%Y', dob) BETWEEN '1981' AND '1991'
5d609582-62c5-4095-a78e-51d4574f8ac6	formula_1	Find the full name, Wiki Pedia page link, and date of birth of German drivers born between 1971 and 1985. List it in descending order of date of birth.	SELECT forename, surname, url, dob FROM drivers WHERE nationality = 'German' AND STRFTIME('%Y', dob) BETWEEN '1971' AND '1985' ORDER BY dob DESC
7751cbe1-a787-4de4-bbad-e9beed1807c2	formula_1	In which location does the Hungaroring circuit located? Also, find the country and coordinates of this circuit?	SELECT country, lat, lng FROM circuits WHERE name = 'Hungaroring'
535e34b5-b627-48d5-b7b7-807d3cb13b35	formula_1	Which constructor scored most points from Monaco Grand Prix between 1980 and 2010? List the score, name and nationality of this team.	SELECT SUM(T1.points), T2.name, T2.nationality FROM constructorResults AS T1 INNER JOIN constructors AS T2 ON T1.constructorId = T2.constructorId INNER JOIN races AS T3 ON T3.raceid = T1.raceid WHERE T3.name = 'Monaco Grand Prix' AND T3.year BETWEEN 1980 AND 2010 GROUP BY T2.name ORDER BY SUM(T1.points) DESC LIMIT 1
9614cffd-d466-4253-be42-bf594081ad95	formula_1	What is the average score of Lewis Hamilton among all the Turkish Grand Prix?	SELECT AVG(T2.points) FROM drivers AS T1 INNER JOIN driverStandings AS T2 ON T1.driverId = T2.driverId INNER JOIN races AS T3 ON T3.raceId = T2.raceId WHERE T1.forename = 'Lewis' AND T1.surname = 'Hamilton' AND T3.name = 'Turkish Grand Prix'
10cb60d6-8295-4341-88fb-e3cff0a9e9a2	thrombosis_prediction	What was the gender of the first AORTITIS diagnosed patient?	SELECT SEX FROM Patient WHERE Diagnosis = 'AORTITIS' AND `First Date` IS NOT NULL ORDER BY `First Date` ASC LIMIT 1
7df70dd8-eb41-4741-949b-84fcea190b86	formula_1	What is the annual average number of races held during the first 10 years of the 21st century?	SELECT CAST(SUM(CASE WHEN year BETWEEN 2000 AND 2010 THEN 1 ELSE 0 END) AS REAL) / 10 FROM races WHERE date BETWEEN '2000-01-01' AND '2010-12-31'
674ffa7c-2522-491d-89a5-3053120886bf	formula_1	Which citizenship do the vast majority of the drivers hold?	SELECT nationality FROM drivers GROUP BY nationality ORDER BY COUNT(driverId) DESC LIMIT 1
1fd7cbef-8698-464d-8e7b-df0a95e6510a	formula_1	In terms of number of points acquired, how many victories did the driver who ranked 91st acquired?	SELECT SUM(CASE WHEN points = 91 THEN wins ELSE 0 END) FROM driverStandings
c82c028d-2117-41fa-adae-3ac4f5965bf9	formula_1	In terms of the fastest lap time, what is the name of the race which recorded the fastest lap speed by a racer?	SELECT T1.name FROM races AS T1 INNER JOIN results AS T2 ON T1.raceId = T2.raceId WHERE T2.fastestLapTime IS NOT NULL ORDER BY T2.fastestLapTime ASC LIMIT 1
1ca7de26-c7ac-4cf9-b63c-542819177e97	formula_1	Which racetrack hosted the most recent race? Indicate the full location.	SELECT T1.location FROM circuits AS T1 INNER JOIN races AS T2 ON T1.circuitId = T2.circuitId ORDER BY T2.date DESC LIMIT 1
e7e11a39-32a2-4da5-b6eb-24d5d6bb4926	formula_1	What is full name of the racer who ranked 1st in the 3rd qualifying race held in the Marina Bay Street Circuit in 2008?	SELECT T2.forename, T2.surname FROM qualifying AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId INNER JOIN races AS T3 ON T1.raceid = T3.raceid WHERE q3 IS NOT NULL AND T3.year = 2008 AND T3.circuitId IN ( SELECT circuitId FROM circuits WHERE name = 'Marina Bay Street Circuit' ) ORDER BY CAST(SUBSTR(q3, 1, INSTR(q3, ':') - 1) AS INTEGER) * 60 + CAST(SUBSTR(q3, INSTR(q3, ':') + 1, INSTR(q3, '.') - INSTR(q3, ':') - 1) AS REAL) + CAST(SUBSTR(q3, INSTR(q3, '.') + 1) AS REAL) / 1000 ASC LIMIT 1
b443882b-a76f-4fb1-b666-9976377bc537	formula_1	As of the present, what is the full name of the youngest racer? Indicate her nationality and the name of the race to which he/she first joined.	SELECT T1.forename, T1.surname, T1.nationality, T3.name FROM drivers AS T1 INNER JOIN driverStandings AS T2 on T1.driverId = T2.driverId INNER JOIN races AS T3 on T2.raceId = T3.raceId ORDER BY JULIANDAY(T1.dob) DESC LIMIT 1
fe18ee11-49f4-4384-9925-5f383908fcc9	formula_1	How many accidents did the driver who had the highest number accidents in the Canadian Grand Prix have?	SELECT COUNT(T1.driverId) FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN status AS T3 on T1.statusId = T3.statusId WHERE T3.statusId = 3 AND T2.name = 'Canadian Grand Prix' GROUP BY T1.driverId ORDER BY COUNT(T1.driverId) DESC LIMIT 1
94c832fc-94df-4b58-9bd3-9fbea97c20d0	formula_1	How many wins was achieved by the oldest racer? Indicate his/her full name.	SELECT SUM(T1.wins),T2.forename, T2.surname FROM driverStandings AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId ORDER BY T2.dob ASC LIMIT 1
5ae591ad-7670-40da-a7c3-13529582ac40	formula_1	What was the longest time a driver had ever spent at a pit stop?	SELECT duration FROM pitStops ORDER BY duration DESC LIMIT 1
4a6c75c0-6e86-43da-a91e-c42ff123a98b	formula_1	Among all the lap records set on various circuits, what is the time for the fastest one?	SELECT time FROM lapTimes ORDER BY (CASE WHEN INSTR(time, ':') <> INSTR(SUBSTR(time, INSTR(time, ':') + 1), ':') + INSTR(time, ':') THEN CAST(SUBSTR(time, 1, INSTR(time, ':') - 1) AS REAL) * 3600 ELSE 0 END) + (CAST(SUBSTR(time, INSTR(time, ':') - 2 * (INSTR(time, ':') = INSTR(SUBSTR(time, INSTR(time, ':') + 1), ':') + INSTR(time, ':')), INSTR(time, ':') - 1) AS REAL) * 60) + (CAST(SUBSTR(time, INSTR(time, ':') + 1, INSTR(time, '.') - INSTR(time, ':') - 1) AS REAL)) + (CAST(SUBSTR(time, INSTR(time, '.') + 1) AS REAL) / 1000) ASC LIMIT 1
bb41dd6f-3019-4b4a-9013-7215d1f4279e	formula_1	What was the longest time that Lewis Hamilton had spent at a pit stop?	SELECT T1.duration FROM pitStops AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.forename = 'Lewis' AND T2.surname = 'Hamilton' ORDER BY T1.duration DESC LIMIT 1
e20f2dc9-24e8-4846-8645-5e00df824cfc	formula_1	During which lap did Lewis Hamilton take a pit stop during the 2011 Australian Grand Prix?	SELECT T1.lap FROM pitStops AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId INNER JOIN races AS T3 on T1.raceId = T3.raceId WHERE T2.forename = 'Lewis' AND T2.surname = 'Hamilton' AND T3.year = 2011 AND T3.name = 'Australian Grand Prix'
e5e8e353-9385-467d-a4c7-1e85c3e56810	formula_1	Please list the time each driver spent at the pit stop during the 2011 Australian Grand Prix.	SELECT T1.duration FROM pitStops AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId WHERE T2.year = 2011 AND T2.name = 'Australian Grand Prix'
4e5c689a-83a8-4ce8-b32d-38e70a41a5b4	formula_1	What is the lap record set by Lewis Hamilton in a Formula_1 race?	SELECT T1.time FROM lapTimes AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.forename = 'Lewis' AND T2.surname = 'Hamilton'
e1878b7b-af81-4ef0-85c7-e13a2323a7e1	formula_1	Which top 20 driver created the shortest lap time ever record in a Formula_1 race? Please give them full names.	WITH lap_times_in_seconds AS (SELECT driverId, (CASE WHEN SUBSTR(time, 1, INSTR(time, ':') - 1) <> '' THEN CAST(SUBSTR(time, 1, INSTR(time, ':') - 1) AS REAL) * 60 ELSE 0 END + CASE WHEN SUBSTR(time, INSTR(time, ':') + 1, INSTR(time, '.') - INSTR(time, ':') - 1) <> '' THEN CAST(SUBSTR(time, INSTR(time, ':') + 1, INSTR(time, '.') - INSTR(time, ':') - 1) AS REAL) ELSE 0 END + CASE WHEN SUBSTR(time, INSTR(time, '.') + 1) <> '' THEN CAST(SUBSTR(time, INSTR(time, '.') + 1) AS REAL) / 1000 ELSE 0 END) AS time_in_seconds FROM lapTimes) SELECT T2.forename, T2.surname, T1.driverId FROM (SELECT driverId, MIN(time_in_seconds) AS min_time_in_seconds FROM lap_times_in_seconds GROUP BY driverId) AS T1 INNER JOIN drivers AS T2 ON T1.driverId = T2.driverId ORDER BY T1.min_time_in_seconds ASC LIMIT 20
266d5615-10ed-4c51-a92f-e60a08e0ae9f	formula_1	What was the position of the circuits during Lewis Hamilton's fastest lap in a Formula_1 race?	SELECT T1.position FROM lapTimes AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.forename = 'Lewis' AND T2.surname = 'Hamilton' ORDER BY T1.time ASC LIMIT 1
82d2ac57-94f7-4cc5-b7ea-f080f7f5bae6	formula_1	What is the lap record for the Austrian Grand Prix Circuit?	WITH fastest_lap_times AS ( SELECT T1.raceId, T1.fastestLapTime FROM results AS T1 WHERE T1.FastestLapTime IS NOT NULL) SELECT MIN(fastest_lap_times.fastestLapTime) as lap_record FROM fastest_lap_times INNER JOIN races AS T2 on fastest_lap_times.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId WHERE T2.name = 'Austrian Grand Prix'
164b5bc2-0cdf-44db-8347-c15355f11322	european_football_2	In Scotland Premier League, which away team won the most during the 2010 season?	SELECT teamInfo.team_long_name FROM League AS leagueData INNER JOIN Match AS matchData ON leagueData.id = matchData.league_id INNER JOIN Team AS teamInfo ON matchData.away_team_api_id = teamInfo.team_api_id WHERE leagueData.name = 'Scotland Premier League' AND matchData.season = '2009/2010' AND matchData.away_team_goal - matchData.home_team_goal > 0 GROUP BY matchData.away_team_api_id ORDER BY COUNT(*) DESC LIMIT 1
388da30b-528f-4437-9641-584b27dd8924	european_football_2	What are the speed in which attacks are put together of the top 4 teams with the highest build Up Play Speed?	SELECT t1.buildUpPlaySpeed FROM Team_Attributes AS t1 INNER JOIN Team AS t2 ON t1.team_api_id = t2.team_api_id ORDER BY t1.buildUpPlaySpeed ASC LIMIT 4
9283d4d6-7188-48a4-b502-1b42e941acc8	formula_1	Please list the lap records for the circuits in Italy.	WITH fastest_lap_times AS (SELECT T1.raceId, T1.FastestLapTime, (CAST(SUBSTR(T1.FastestLapTime, 1, INSTR(T1.FastestLapTime, ':') - 1) AS REAL) * 60) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, ':') + 1, INSTR(T1.FastestLapTime, '.') - INSTR(T1.FastestLapTime, ':') - 1) AS REAL)) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, '.') + 1) AS REAL) / 1000) as time_in_seconds FROM results AS T1 WHERE T1.FastestLapTime IS NOT NULL ) SELECT T1.FastestLapTime as lap_record FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId INNER JOIN (SELECT MIN(fastest_lap_times.time_in_seconds) as min_time_in_seconds FROM fastest_lap_times INNER JOIN races AS T2 on fastest_lap_times.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId WHERE T3.country = 'Italy' ) AS T4 ON (CAST(SUBSTR(T1.FastestLapTime, 1, INSTR(T1.FastestLapTime, ':') - 1) AS REAL) * 60) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, ':') + 1, INSTR(T1.FastestLapTime, '.') - INSTR(T1.FastestLapTime, ':') - 1) AS REAL)) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, '.') + 1) AS REAL) / 1000) = T4.min_time_in_seconds LIMIT 1
875cc0ec-0954-46c0-9a18-06b5de30cb8d	formula_1	In which Formula_1 race was the lap record for the Austrian Grand Prix Circuit set?	WITH fastest_lap_times AS ( SELECT T1.raceId, T1.FastestLapTime, (CAST(SUBSTR(T1.FastestLapTime, 1, INSTR(T1.FastestLapTime, ':') - 1) AS REAL) * 60) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, ':') + 1, INSTR(T1.FastestLapTime, '.') - INSTR(T1.FastestLapTime, ':') - 1) AS REAL)) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, '.') + 1) AS REAL) / 1000) as time_in_seconds FROM results AS T1 WHERE T1.FastestLapTime IS NOT NULL ) SELECT T2.name FROM races AS T2 INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId INNER JOIN results AS T1 on T2.raceId = T1.raceId INNER JOIN ( SELECT MIN(fastest_lap_times.time_in_seconds) as min_time_in_seconds FROM fastest_lap_times INNER JOIN races AS T2 on fastest_lap_times.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId WHERE T2.name = 'Austrian Grand Prix') AS T4 ON (CAST(SUBSTR(T1.FastestLapTime, 1, INSTR(T1.FastestLapTime, ':') - 1) AS REAL) * 60) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, ':') + 1, INSTR(T1.FastestLapTime, '.') - INSTR(T1.FastestLapTime, ':') - 1) AS REAL)) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, '.') + 1) AS REAL) / 1000) = T4.min_time_in_seconds WHERE T2.name = 'Austrian Grand Prix'
76697087-a946-4888-b380-9b31194686a0	formula_1	In the race a driver set the lap record for the Austrian Grand Prix Circuit, how long did he spent at the pit stop at that same race?	WITH fastest_lap_times AS ( SELECT T1.raceId, T1.driverId, T1.FastestLapTime, (CAST(SUBSTR(T1.FastestLapTime, 1, INSTR(T1.FastestLapTime, ':') - 1) AS REAL) * 60) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, ':') + 1, INSTR(T1.FastestLapTime, '.') - INSTR(T1.FastestLapTime, ':') - 1) AS REAL)) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, '.') + 1) AS REAL) / 1000) as time_in_seconds FROM results AS T1 WHERE T1.FastestLapTime IS NOT NULL), lap_record_race AS ( SELECT T1.raceId, T1.driverId FROM results AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId INNER JOIN ( SELECT MIN(fastest_lap_times.time_in_seconds) as min_time_in_seconds FROM fastest_lap_times INNER JOIN races AS T2 on fastest_lap_times.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId WHERE T2.name = 'Austrian Grand Prix') AS T4 ON (CAST(SUBSTR(T1.FastestLapTime, 1, INSTR(T1.FastestLapTime, ':') - 1) AS REAL) * 60) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, ':') + 1, INSTR(T1.FastestLapTime, '.') - INSTR(T1.FastestLapTime, ':') - 1) AS REAL)) + (CAST(SUBSTR(T1.FastestLapTime, INSTR(T1.FastestLapTime, '.') + 1) AS REAL) / 1000) = T4.min_time_in_seconds WHERE T2.name = 'Austrian Grand Prix') SELECT T4.duration FROM lap_record_race INNER JOIN pitStops AS T4 on lap_record_race.raceId = T4.raceId AND lap_record_race.driverId = T4.driverId
5a43c518-393f-44bc-864c-a50a99a75079	formula_1	Please list the location coordinates of the circuits whose lap record is 1:29.488.	SELECT T3.lat, T3.lng FROM lapTimes AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId WHERE T1.time = '1:29.488'
01ba0cc3-fe0b-4517-84f5-796c3120d98d	formula_1	What was the average time in milliseconds Lewis Hamilton spent at a pit stop during Formula_1 races?	SELECT AVG(milliseconds) FROM pitStops AS T1 INNER JOIN drivers AS T2 on T1.driverId = T2.driverId WHERE T2.forename = 'Lewis' AND T2.surname = 'Hamilton'
5ab2f273-ddc4-4dc0-a8ae-26f76d9c5fd8	formula_1	What is the average lap time in milliseconds of all the lap records set on the various circuits in Italy?	SELECT CAST(SUM(T1.milliseconds) AS REAL) / COUNT(T1.lap) FROM lapTimes AS T1 INNER JOIN races AS T2 on T1.raceId = T2.raceId INNER JOIN circuits AS T3 on T2.circuitId = T3.circuitId WHERE T3.country = 'Italy'
6faa0495-c0b9-46e1-ba48-2584157c0397	european_football_2	Which player has the highest overall rating? Indicate the player's api id.	SELECT player_api_id FROM Player_Attributes ORDER BY overall_rating DESC LIMIT 1
3573e823-01f9-49c7-b12e-ea346b6a0229	european_football_2	What is the height of the tallest player? Indicate his name.	SELECT player_name FROM Player ORDER BY height DESC LIMIT 1
7e8346bb-706e-4bb0-8784-c970de1c2bf4	european_football_2	What is the preferred foot when attacking of the player with the lowest potential?	SELECT preferred_foot FROM Player_Attributes WHERE potential IS NOT NULL ORDER BY potential ASC LIMIT 1
d625e121-11e9-4134-8170-d43b4600ae2c	european_football_2	Among the players with an overall rating between 60 to 65, how many players whose going to be in all of your attack moves instead of defensing?	SELECT COUNT(id) FROM Player_Attributes WHERE overall_rating BETWEEN 60 AND 65 AND defensive_work_rate = 'low'
5d905c92-16c9-48fd-9a23-cfb4c5c94b41	european_football_2	Who are the top 5 players who perform better in crossing actions? Indicate their player id.	SELECT id FROM Player_Attributes ORDER BY crossing DESC LIMIT 5
96eaed3c-64ed-4b2b-910c-a23312628f0e	european_football_2	Give the name of the league had the most goals in the 2016 season?	SELECT t2.name FROM Match AS t1 INNER JOIN League AS t2 ON t1.league_id = t2.id WHERE t1.season = '2015/2016' GROUP BY t2.name ORDER BY SUM(t1.home_team_goal + t1.away_team_goal) DESC LIMIT 1
4b815fd5-86ea-4efa-ae1e-52a2f1b51cd6	european_football_2	Which home team had lost the fewest matches in the 2016 season?	SELECT teamDetails.team_long_name FROM Match AS matchData INNER JOIN Team AS teamDetails ON matchData.home_team_api_id = teamDetails.team_api_id WHERE matchData.season = '2015/2016' AND matchData.home_team_goal - matchData.away_team_goal < 0 GROUP BY matchData.home_team_api_id ORDER BY COUNT(*) ASC LIMIT 1
cf8e2d56-127a-400b-9d4e-787076d611bc	european_football_2	Indicate the full names of the top 10 players with the highest number of penalties.	SELECT t2.player_name FROM Player_Attributes AS t1 INNER JOIN Player AS t2 ON t1.id = t2.id ORDER BY t1.penalties DESC LIMIT 10
ff56631a-feb9-4696-8f5f-c20a7f3bb81d	european_football_2	Give the name of the league had the most matches end as draw in the 2016 season?	SELECT t2.name FROM Match AS t1 INNER JOIN League AS t2 ON t1.league_id = t2.id WHERE t1.season = '2015/2016' AND t1.home_team_goal = t1.away_team_goal GROUP BY t2.name ORDER BY COUNT(t1.id) DESC LIMIT 1
1b5eb758-7910-480f-aad1-f46b82a514be	european_football_2	At present, calculate for the player's age who have a sprint speed of no less than 97 between 2013 to 2015.	SELECT DISTINCT DATETIME() - T2.birthday age FROM Player_Attributes AS t1 INNER JOIN Player AS t2 ON t1.player_api_id = t2.player_api_id WHERE STRFTIME('%Y',t1.`date`) >= '2013' AND STRFTIME('%Y',t1.`date`) <= '2015' AND t1.sprint_speed >= 97
7ec560c6-388d-4cfb-b707-b2e270d74d7e	european_football_2	Give the name of the league with the highest matches of all time and how many matches were played in the said league.	SELECT t2.name, t1.max_count FROM League AS t2 JOIN (SELECT league_id, MAX(cnt) AS max_count FROM (SELECT league_id, COUNT(id) AS cnt FROM Match GROUP BY league_id) AS subquery) AS t1 ON t1.league_id = t2.id
ad752827-07a6-4e56-af73-42fbd426a219	european_football_2	What is the average height of players born between 1990 and 1995?	SELECT SUM(height) / COUNT(id) FROM Player WHERE SUBSTR(birthday, 1, 4) BETWEEN '1990' AND '1995'
91658de2-3481-4670-abb8-7ed04c51f3ec	european_football_2	List the players' api id who had the highest above average overall ratings in 2010.	SELECT player_api_id FROM Player_Attributes WHERE SUBSTR(`date`, 1, 4) = '2010' ORDER BY overall_rating DESC LIMIT 1
b2ef31ab-fdb1-4f01-9da7-21496ebb7d5e	european_football_2	Give the team_fifa_api_id of teams with more than 50 but less than 60 build-up play speed.	SELECT DISTINCT team_fifa_api_id FROM Team_Attributes WHERE buildUpPlaySpeed > 50 AND buildUpPlaySpeed < 60
e62b77fe-e609-4c5b-b8df-ba59d2868e96	european_football_2	List the long name of teams with above-average build-up play passing in 2012.	SELECT DISTINCT t4.team_long_name FROM Team_Attributes AS t3 INNER JOIN Team AS t4 ON t3.team_api_id = t4.team_api_id WHERE SUBSTR(t3.`date`, 1, 4) = '2012' AND t3.buildUpPlayPassing > ( SELECT CAST(SUM(t2.buildUpPlayPassing) AS REAL) / COUNT(t1.id) FROM Team AS t1 INNER JOIN Team_Attributes AS t2 ON t1.team_api_id = t2.team_api_id WHERE STRFTIME('%Y',t2.`date`) = '2012')
8fc8a641-fe78-47a8-a2ee-6d92b68629f0	european_football_2	Calculate the percentage of players who prefer left foot, who were born between 1987 and 1992.	SELECT CAST(COUNT(CASE WHEN t2.preferred_foot = 'left' THEN t1.id ELSE NULL END) AS REAL) * 100 / COUNT(t1.id) percent FROM Player AS t1 INNER JOIN Player_Attributes AS t2 ON t1.player_api_id = t2.player_api_id WHERE SUBSTR(t1.birthday, 1, 4) BETWEEN '1987' AND '1992'
4fcafef8-c905-4136-ac9a-763d9b155ca1	european_football_2	List the top 5 leagues in ascending order of the number of goals made in all seasons combined.	SELECT t1.name, SUM(t2.home_team_goal) + SUM(t2.away_team_goal) FROM League AS t1 INNER JOIN Match AS t2 ON t1.id = t2.league_id GROUP BY t1.name ORDER BY SUM(t2.home_team_goal) + SUM(t2.away_team_goal) ASC LIMIT 5
3a6d6e14-1da9-4aec-a445-8b272fe1b85e	european_football_2	Find the average number of long-shot done by Ahmed Samir Farag.	SELECT CAST(SUM(t2.long_shots) AS REAL) / COUNT(t2.`date`) FROM Player AS t1 INNER JOIN Player_Attributes AS t2 ON t1.player_api_id = t2.player_api_id WHERE t1.player_name = 'Ahmed Samir Farag'
03f1af7e-fe0c-49dc-97d6-18a592e76b2d	european_football_2	List the top 10 players' names whose heights are above 180 in descending order of average heading accuracy.	SELECT t1.player_name FROM Player AS t1 INNER JOIN Player_Attributes AS t2 ON t1.player_api_id = t2.player_api_id WHERE t1.height > 180 GROUP BY t1.id ORDER BY CAST(SUM(t2.heading_accuracy) AS REAL) / COUNT(t2.`player_fifa_api_id`) DESC LIMIT 10
5202bedf-b72b-4c23-b5b0-b65bc7373e5a	european_football_2	For the teams with normal build-up play dribbling class in 2014, List the names of the teams with less than average chance creation passing, in descending order of chance creation passing.	SELECT t3.team_long_name FROM Team AS t3 INNER JOIN Team_Attributes AS t4 ON t3.team_api_id = t4.team_api_id WHERE t4.buildUpPlayDribblingClass = 'Normal' AND t4.chanceCreationPassing < ( SELECT CAST(SUM(t2.chanceCreationPassing) AS REAL) / COUNT(t1.id) FROM Team AS t1 INNER JOIN Team_Attributes AS t2 ON t1.team_api_id = t2.team_api_id WHERE t2.buildUpPlayDribblingClass = 'Normal' AND SUBSTR(t2.`date`, 1, 4) = '2014') ORDER BY t4.chanceCreationPassing DESC
6f5bf1fd-ffba-4cc6-8898-557401d612fa	european_football_2	List the name of leagues in which the average goals by the home team is higher than the away team in the 2009/2010 season.	SELECT t1.name FROM League AS t1 INNER JOIN Match AS t2 ON t1.id = t2.league_id WHERE t2.season = '2009/2010' GROUP BY t1.name HAVING (CAST(SUM(t2.home_team_goal) AS REAL) / COUNT(DISTINCT t2.id)) - (CAST(SUM(t2.away_team_goal) AS REAL) / COUNT(DISTINCT t2.id)) > 0
d181d465-c31f-4e38-9885-dd5c552044b0	european_football_2	What is the short name of the football team Queens Park Rangers?	SELECT team_short_name FROM Team WHERE team_long_name = 'Queens Park Rangers'
87a0cc21-d07a-4686-bf88-a31605ddf7fa	european_football_2	List the football players with a birthyear of 1970 and a birthmonth of October.	SELECT player_name FROM Player WHERE SUBSTR(birthday, 1, 7) = '1970-10'
