1ae4c704-697f-4ce0-9ada-fe6199559f9d	european_football_2	How many matches in the 2015/2016 season were held in Scotland Premier League\n?	SELECT COUNT(t2.id) FROM League AS t1 INNER JOIN Match AS t2 ON t1.id = t2.league_id WHERE t2.season = '2015/2016' AND t1.name = 'Scotland Premier League'
