ad8838ac-60b7-44a1-9425-d05012a28972	european_football_2	What was the chance creation crossing class for "Hull City" on 2010/2/22?	SELECT t2.chanceCreationCrossingClass FROM Team AS t1 INNER JOIN Team_Attributes AS t2 ON t1.team_api_id = t2.team_api_id WHERE t1.team_long_name = 'Hull City' AND SUBSTR(t2.`date`, 1, 10) = '2010-02-22'
e9726849-2121-4ce0-93be-48ea60d8c12a	european_football_2	For the team "Hannover 96", what was its defence aggression class on 2015/9/10?	SELECT t2.chanceCreationShootingClass FROM Team AS t1 INNER JOIN Team_Attributes AS t2 ON t1.team_api_id = t2.team_api_id WHERE t1.team_long_name = 'Hannover 96' AND t2.`date` LIKE '2015-09-10%'
03bfd5f1-3247-4e46-b4d7-a7c3c148957d	european_football_2	What was the average overall rating for Marko Arnautovic from 2007/2/22 to 2016/4/21?	SELECT CAST(SUM(t2.overall_rating) AS REAL) / COUNT(t2.id) FROM Player AS t1 INNER JOIN Player_Attributes AS t2 ON t1.player_fifa_api_id = t2.player_fifa_api_id WHERE t1.player_name = 'Marko Arnautovic' AND SUBSTR(t2.`date`, 1, 10) BETWEEN '2007-02-22' AND '2016-04-21'
b749af4b-dbc6-464e-aa02-25d6db6b1745	european_football_2	What percentage is Landon Donovan's overall rating higher than Jordan Bowery on 2013/7/12?	SELECT (SUM(CASE WHEN t1.player_name = 'Landon Donovan' THEN t2.overall_rating ELSE 0 END) * 1.0 - SUM(CASE WHEN t1.player_name = 'Jordan Bowery' THEN t2.overall_rating ELSE 0 END)) * 100 / SUM(CASE WHEN t1.player_name = 'Landon Donovan' THEN t2.overall_rating ELSE 0 END) LvsJ_percent FROM Player AS t1 INNER JOIN Player_Attributes AS t2 ON t1.player_fifa_api_id = t2.player_fifa_api_id WHERE SUBSTR(t2.`date`, 1, 10) = '2013-07-12'
41f0491e-0741-404a-a9ef-00f7aedaa0ea	european_football_2	List down most tallest players' name.	SELECT player_name FROM (SELECT player_name, height, DENSE_RANK() OVER (ORDER BY height DESC) as rank FROM Player) WHERE rank = 1
