a46cb4ab-8136-4463-bbfc-c91e3682bbff	european_football_2	State the name of the most strongest player.	SELECT DISTINCT t1.player_name FROM Player AS t1 INNER JOIN Player_Attributes AS t2 ON t1.player_api_id = t2.player_api_id WHERE t2.overall_rating = (SELECT MAX(overall_rating) FROM Player_Attributes)
