5e12ae68-d18a-4ed4-95a6-9253ce263d2a	thrombosis_prediction	What is the ratio of outpatient to inpatient followed up treatment among all the 'SLE' diagnosed patient?	SELECT SUM(CASE WHEN Admission = '+' THEN 1.0 ELSE 0 END) / SUM(CASE WHEN Admission = '-' THEN 1 ELSE 0 END) FROM Patient WHERE Diagnosis = 'SLE'
01ba697f-de6d-4611-a2bd-bf5789d38159	thrombosis_prediction	What is the disease patient '30609' diagnosed with. List all the date of laboratory tests done for this patient.	SELECT T1.Diagnosis, T2.Date FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T1.ID = 30609
cd182e26-9892-4bc0-a7e9-9552efc54084	thrombosis_prediction	State the sex and birthday of patient ID '163109'. When was the examination taken and what symptom does the patient had.	SELECT T1.SEX, T1.Birthday, T2.`Examination Date`, T2.Symptoms FROM Patient AS T1 INNER JOIN Examination AS T2 ON T1.ID = T2.ID WHERE T1.ID = 163109
51df2b51-232d-4867-ab7b-3162bbc25f11	thrombosis_prediction	List the patient ID, sex and birthday of patient with LDH beyond normal range.	SELECT DISTINCT T1.ID, T1.SEX, T1.Birthday FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.LDH > 500
c83765a7-7c84-431f-affd-405837c52854	thrombosis_prediction	State the ID and age of patient with positive degree of coagulation.	SELECT DISTINCT T1.ID, STRFTIME('%Y', CURRENT_TIMESTAMP) - STRFTIME('%Y', T1.Birthday) FROM Patient AS T1 INNER JOIN Examination AS T2 ON T1.ID = T2.ID WHERE T2.RVVT = '+'
60967e3d-cbd2-409f-bcd5-712ff4cc7315	thrombosis_prediction	For patients with severe degree of thrombosis, list their ID, sex and disease the patient is diagnosed with.	SELECT DISTINCT T1.ID, T1.SEX, T1.Diagnosis FROM Patient AS T1 INNER JOIN Examination AS T2 ON T1.ID = T2.ID WHERE T2.Thrombosis = 2
048cca8a-383b-4222-a084-95a658d03013	thrombosis_prediction	List all patients who were born in 1937 whose total cholesterol was beyond the normal range.	SELECT DISTINCT T1.ID FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE STRFTIME('%Y', T1.Birthday) = '1937' AND T2.`T-CHO` >= 250
b061437c-22c3-4ba0-ab40-30a31b7dd799	thrombosis_prediction	For patient with albumin level lower than 3.5, list their ID, sex and diagnosis.	SELECT DISTINCT T1.ID, T1.SEX, T1.Diagnosis FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.ALB < 3.5
246a28c3-7eee-4bcd-b869-f3a723dc8e90	thrombosis_prediction	What is the percentage of female patient had total protein not within the normal range?	SELECT CAST(SUM(CASE WHEN T1.SEX = 'F' AND (T2.TP < 6.0 OR T2.TP > 8.5) THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T1.SEX = 'F'
e162abde-dfb5-4794-a283-b489458aab9b	thrombosis_prediction	For in-patient age 50 and above, what is their average anti-cardiolipin antibody (IgG) concentration?	SELECT AVG(T2.`aCL IgG`) FROM Patient AS T1 INNER JOIN Examination AS T2 ON T1.ID = T2.ID WHERE STRFTIME('%Y', CURRENT_TIMESTAMP) - STRFTIME('%Y', T1.Birthday) >= 50 AND T1.Admission = '+'
