cc35b690-4808-4280-8b3b-445871581ac0	thrombosis_prediction	Among the patients with the normal level of triglyceride, how many of them have other symptoms observed?	SELECT COUNT(T1.ID) FROM Examination AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.TG < 200 AND T1.Symptoms IS NOT NULL
faa1b1ad-6b66-43a3-ae74-e7d82967096f	thrombosis_prediction	What is the disease name of the patient who has the highest level of triglyceride within the normal range?	SELECT T1.Diagnosis FROM Examination AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.TG < 200 ORDER BY T2.TG DESC LIMIT 1
86f6d5d6-b6b2-4cf4-9677-854de94c6e58	thrombosis_prediction	Please list the IDs of the patients with no thrombosis and an abnormal level of creatinine phosphokinase.	SELECT DISTINCT T1.ID FROM Laboratory AS T1 INNER JOIN Examination AS T2 ON T1.ID = T2.ID WHERE T2.Thrombosis = 0 AND T1.CPK < 250
eaef2fab-ece5-441f-8a76-b255576ccab3	thrombosis_prediction	For the patients with a normal range of creatinine phosphokinase, how many of them have a positive measure of degree of coagulation?	SELECT COUNT(T1.ID) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID INNER JOIN Examination AS T3 ON T1.ID = T3.ID WHERE T2.CPK < 250 AND (T3.KCT = '+' OR T3.RVVT = '+' OR T3.LAC = '+')
eb975fd3-fbaf-45f6-a117-40cd8ba375d2	thrombosis_prediction	When is the birthday of the oldest patient whose blood glucose is abnormal?	SELECT T1.Birthday FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.GLU > 180 ORDER BY T1.Birthday ASC LIMIT 1
6c7bf27c-bd42-4871-bb72-10f2530b0ed2	thrombosis_prediction	Among the patients with a normal blood glucose, how many of them don't have thrombosis?	SELECT COUNT(T1.ID) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID INNER JOIN Examination AS T3 ON T1.ID = T3.ID WHERE T2.GLU < 180 AND T3.Thrombosis = 0
372c5952-c45c-4e2f-a54b-b27e4d8a9358	thrombosis_prediction	How many patients accepted to the hospital have a normal level of white blood cells?	SELECT COUNT(T1.ID) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.WBC BETWEEN 3.5 AND 9 AND T1.Admission = '+'
abe98127-6935-46a3-a443-5cdec42900b3	thrombosis_prediction	How many patients diagnosed with SLE have a normal white blood cell level?	SELECT COUNT(T1.ID) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T1.Diagnosis = 'SLE' AND T2.WBC BETWEEN 3.5 AND 9
ccfee345-be14-45e3-9eba-777680490d94	thrombosis_prediction	Please list the patient's ID if he or she has an abnormal level of red blood cell and is followed at the outpatient clinic.	SELECT DISTINCT T1.ID FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE (T2.RBC <= 3.5 OR T2.RBC >= 6) AND T1.Admission = '-'
24320ad0-0e1b-4e3f-b6e7-255c29915dbb	thrombosis_prediction	Among the patients who have a normal platelet level, how many of them have other symptoms observed?	SELECT COUNT(T1.ID) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.PLT > 100 AND T2.PLT < 400 AND T1.Diagnosis IS NOT NULL
82f171d6-ab49-4403-b330-f337dc8e613b	thrombosis_prediction	Please list a patient's platelet level if it is within the normal range and if he or she is diagnosed with MCTD.	SELECT T2.PLT FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T1.Diagnosis = 'MCTD' AND T2.PLT BETWEEN 100 AND 400
b25a7615-910a-4884-99cf-47e03ca65da4	thrombosis_prediction	For the male patients that have a normal prothrombin time, what is their average prothrombin time?	SELECT AVG(T2.PT) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID WHERE T2.PT < 14 AND T1.SEX = 'M'
ad2416ea-e688-4038-8ecc-8d51049d4602	thrombosis_prediction	How many patients with severe thrombosis have a normal prothrombin time?	SELECT COUNT(T1.ID) FROM Patient AS T1 INNER JOIN Laboratory AS T2 ON T1.ID = T2.ID INNER JOIN Examination AS T3 ON T1.ID = T3.ID WHERE T2.PT < 14 AND T3.Thrombosis < 3 AND T3.Thrombosis > 0
16ddd993-30a3-4a8c-aa38-c2ce5502a994	student_club	What's Angela Sanders's major?	SELECT T2.major_name FROM member AS T1 INNER JOIN major AS T2 ON T1.link_to_major = T2.major_id WHERE T1.first_name = 'Angela' AND T1.last_name = 'Sanders'
81d0144f-9c00-4c0f-8314-6e65cc141134	student_club	How many students in the Student_Club are from the College of Engineering?	SELECT COUNT(T1.member_id) FROM member AS T1 INNER JOIN major AS T2 ON T1.link_to_major = T2.major_id WHERE T2.college = 'College of Engineering'
59903263-6c25-4b7f-93cd-f87fa1d933c0	student_club	Please list the full names of the students in the Student_Club that come from the Art and Design Department.	SELECT T1.first_name, T1.last_name FROM member AS T1 INNER JOIN major AS T2 ON T1.link_to_major = T2.major_id WHERE T2.department = 'Art and Design Department'
e59e69b0-475c-4265-9fde-61968fe5ad93	student_club	How many students of the Student_Club have attended the event "Women's Soccer"?	SELECT COUNT(T1.event_id) FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event WHERE T1.event_name = 'Women''s Soccer'
9cf816bd-be2b-466e-9ccb-f615db7cbb0a	student_club	Please list the phone numbers of the students from the Student_Club that has attended the event "Women's Soccer".	SELECT T3.phone FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event INNER JOIN member AS T3 ON T2.link_to_member = T3.member_id WHERE T1.event_name = 'Women''s Soccer'
65cf845e-fd1f-4221-a42f-36a1ccd1d915	student_club	Among the students from the Student_Club who attended the event "Women's Soccer", how many of them want a T-shirt that's in medium size?	SELECT COUNT(T1.event_id) FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event INNER JOIN member AS T3 ON T2.link_to_member = T3.member_id WHERE T1.event_name = 'Women''s Soccer' AND T3.t_shirt_size = 'Medium'
ef6a5907-c553-42ad-8fb9-e0d624289389	student_club	What is the event that has the highest attendance of the students from the Student_Club?	SELECT T1.event_name FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event GROUP BY T1.event_name ORDER BY COUNT(T2.link_to_event) DESC LIMIT 1
91cd16d5-a86c-4ef0-a9c0-d0caafcc84f4	student_club	Which college is the vice president of the Student_Club from?	SELECT T2.college FROM member AS T1 INNER JOIN major AS T2 ON T1.link_to_major = T2.major_id WHERE T1.position LIKE 'vice president'
712706e7-84f5-4417-8c31-a1f00ba9e4c9	student_club	Please list the event names of all the events attended by Maya Mclean.	SELECT T1.event_name FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event INNER JOIN member AS T3 ON T2.link_to_member = T3.member_id WHERE T3.first_name = 'Maya' AND T3.last_name = 'Mclean'
dfe3087e-b199-4692-9f40-6bf180b4c71f	student_club	How many events of the Student_Club did Sacha Harrison attend in 2019?	SELECT COUNT(T1.event_id) FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event INNER JOIN member AS T3 ON T2.link_to_member = T3.member_id WHERE T3.first_name = 'Sacha' AND T3.last_name = 'Harrison' AND SUBSTR(T1.event_date, 1, 4) = '2019'
8c404a3f-3bc4-4853-b72e-3d098173208b	student_club	Among the events attended by more than 10 members of the Student_Club, how many of them are meetings?	SELECT T1.event_name FROM event AS T1  INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event GROUP BY T1.event_id  HAVING COUNT(T2.link_to_event) > 10 EXCEPT SELECT T1.event_name  FROM event AS T1  WHERE T1.type = 'Meeting'
3d30d3bd-0ce1-430b-939c-70aea5c344bc	student_club	List all the names of events that had an attendance of over 20 students but were not fundraisers.	SELECT T1.event_name FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event GROUP BY T1.event_id HAVING COUNT(T2.link_to_event) > 20 EXCEPT SELECT T1.event_name FROM event AS T1  WHERE T1.type = 'Fundraiser'
04fda89d-f151-43f1-8e9f-0d85182ac625	student_club	What is the average attendance of meetings in 2020?	SELECT CAST(COUNT(T2.link_to_event) AS REAL) / COUNT(DISTINCT T2.link_to_event) FROM event AS T1 INNER JOIN attendance AS T2 ON T1.event_id = T2.link_to_event WHERE SUBSTR(T1.event_date, 1, 4) = '2020' AND T1.type = 'Meeting'
0db4c73d-a38f-4c32-a5fb-e89647fc9bbb	student_club	What is the most expensive item that was spent in support of club events?	SELECT expense_description FROM expense ORDER BY cost DESC LIMIT 1
