f8919e38-8230-48db-8a71-e22025dea950	student_club	List the full name of all the members of the Student_Club who attended the "Laugh Out Loud" event.	SELECT T1.first_name, T1.last_name FROM member AS T1 INNER JOIN attendance AS T2 ON T1.member_id = T2.link_to_member INNER JOIN event AS T3 ON T2.link_to_event = T3.event_id WHERE T3.event_name = 'Laugh Out Loud'
2c8c4014-f444-437b-aba5-bb38f4118330	student_club	List the last name of all the students who majored Law and Constitutional Studies. \n	SELECT T1.last_name FROM member AS T1 INNER JOIN major AS T2 ON T1.link_to_major = T2.major_id WHERE T2.major_name = 'Law and Constitutional Studies'
