e9138048-77ea-432a-aabe-b62c7c5de0fc	student_club	What college offers the major that Tyler Hewitt took?	SELECT T2.college FROM member AS T1 INNER JOIN major AS T2 ON T1.link_to_major = T2.major_id WHERE T1.first_name = 'Tyler' AND T1.last_name = 'Hewitt'
0e2e38fb-3bd0-4e5c-8310-18e30009ba0d	student_club	What is the amount of the funds that the Vice President received?	SELECT T2.amount FROM member AS T1 INNER JOIN income AS T2 ON T1.member_id = T2.link_to_member WHERE T1.position = 'Vice President'
8ad14ef9-972e-49fd-ba94-b2cd53ecb02c	student_club	How much did the Student_Club members spend on food in September Meeting?	SELECT T2.spent FROM event AS T1 INNER JOIN budget AS T2 ON T1.event_id = T2.link_to_event WHERE T1.event_name = 'September Meeting' AND T2.category = 'Food' AND SUBSTR(T1.event_date, 6, 2) = '09'
a7e8b234-4158-43e9-8210-574afdc48c89	student_club	What city and state did the President of the Student_Club grow up?	SELECT T2.city, T2.state FROM member AS T1 INNER JOIN zip_code AS T2 ON T1.zip = T2.zip_code WHERE T1.position = 'President'
f520b39e-54ac-4946-969d-10b6e69e21ba	student_club	List the full name of the Student_Club members that grew up in Illinois state.	SELECT T1.first_name, T1.last_name FROM member AS T1 INNER JOIN zip_code AS T2 ON T1.zip = T2.zip_code WHERE T2.state = 'Illinois'
13a0a5a3-874a-4e5c-ade0-220e404d9fe3	student_club	How much did the Student_Club members spend on advertisement in September Meeting?	SELECT T2.spent FROM event AS T1 INNER JOIN budget AS T2 ON T1.event_id = T2.link_to_event WHERE T1.event_name = 'September Meeting' AND T2.category = 'Advertisement' AND SUBSTR(T1.event_date, 6, 2) = '09'
624b587b-10b2-4a03-b207-686122c5301b	student_club	What department offers the major that Pierce and Guidi took?	SELECT T2.department FROM member AS T1 INNER JOIN major AS T2 ON T1.link_to_major = T2.major_id WHERE T1.last_name = 'Pierce' OR T1.last_name = 'Guidi'
fd9e77f2-ef2e-42e5-9368-09972862682b	student_club	What is the total budgeted amount for all category in "October Speaker" event?	SELECT SUM(T2.amount) FROM event AS T1 INNER JOIN budget AS T2 ON T1.event_id = T2.link_to_event WHERE T1.event_name = 'October Speaker'
f2788888-cd38-4982-a97b-4b016bbf23a9	student_club	Was each expense in October Meeting on October 8, 2019 approved?	SELECT T3.approved FROM event AS T1 INNER JOIN budget AS T2 ON T1.event_id = T2.link_to_event INNER JOIN expense AS T3 ON T2.budget_id = T3.link_to_budget WHERE T1.event_name = 'October Meeting' AND T1.event_date LIKE '2019-10-08%'
7cf091ee-8039-471a-8da3-b9b3d7e82580	student_club	Calculate the total average cost that Elijah Allen spent in the events on September and October.	SELECT AVG(T2.cost) FROM member AS T1 INNER JOIN expense AS T2 ON T1.member_id = T2.link_to_member WHERE T1.last_name = 'Allen' AND T1.first_name = 'Elijah' AND (SUBSTR(T2.expense_date, 6, 2) = '09' OR SUBSTR(T2.expense_date, 6, 2) = '10')
6669bea0-4c3a-4b74-bce5-a7671062920f	student_club	Calculate the difference of the total amount spent in all events by the Student_Club in year 2019 and 2020.	SELECT SUM(CASE WHEN SUBSTR(T1.event_date, 1, 4) = '2019' THEN T2.spent ELSE 0 END) - SUM(CASE WHEN SUBSTR(T1.event_date, 1, 4) = '2020' THEN T2.spent ELSE 0 END) AS num FROM event AS T1 INNER JOIN budget AS T2 ON T1.event_id = T2.link_to_event
ab2e6b71-42b5-4074-914e-98a44fb64408	student_club	Give the location for "Spring Budget Review".	SELECT location FROM event WHERE event_name = 'Spring Budget Review'
0102ee6e-bdef-4c9b-b178-18141b7b9214	student_club	What was the cost for the "Posters" on 2019/9/4?	SELECT cost FROM expense WHERE expense_description = 'Posters' AND expense_date = '2019-09-04'
